A;EACA,YAAA;EACA,kBAAA;A5ByhJF;;A4BthJA;EACE,0BAAA;EACA,yBAAA;EACA,kBAAA;EACA,WAAA;EACA,WAAA;EACA,YAAA;EACA,QAAA;EACA,2BAAA;EACA,yBAAA;EACA,kBAAA;EACA,aAAA;EACA,uBAAA;EACA,mBAAA;EACA,eAAA;EACF,kBAAA;EACA,gBAAA;EACA,iBAAA;EACA,cAAA;A5ByhJA;;A4BthJA;EACE,cAAA;A5ByhJF;;A4BvhJA;EACE,mBAAA;A5B0hJF;;A4BxhJA;EACE,8BAAA;A5B2hJF;;A4BzhJA;EACE,sBAAA;EACA,gBAAA;A5B4hJF;;A4B1hJA;EACE,aAAA;A5B6hJF;;A4B1hJA;EACE;IACE,aAAA;E5B6hJF;E4B3hJA;IACE,aAAA;E5B6hJF;E4B3hJA;IACE,cAAA;E5B6hJF;AACF;A6BxmJI;EACI,8BAAA;EACA,kBAAA;A7B0mJR;;A6BvmJA;EACI,gBAAA;EACA,yBAAA;EACA,gBAAA;EACA,YAAA;EACA,mBAAA;A7B0mJJ;A6BxmJI;EACI,aAAA;EACA,aAAA;EACA,sBAAA;EACA,WAAA;A7B0mJR;A6BzmJQ;EACI,mBAAA;EACA,SAAA;A7B2mJZ;A6B1mJY;EACI,cAAA;EACA,YAAA;A7B4mJhB;A6B1mJY;EACI,eAAA;EACA,gBAAA;EACA,kBAAA;A7B4mJhB;A6BxmJI;EACI,6BAAA;EACA,kBAAA;A7B0mJR;A6BzmJQ;EACI,SAAA;A7B2mJZ;A6BzmJQ;EACI,cAAA;EACA,eAAA;EAEA,gBAAA;EACA,mBAAA;EACA,WAAA;EACA,yBAAA;EACA,iBAAA;A7B0mJZ","file":"style.css","sourcesContent":["/*=== MEDIA QUERY ===*/\n@mixin mobile-xs{\n  @media(max-width:400px){\n    @content;\n  }\n}\n@mixin mobile{\n  @media(max-width:480px){\n    @content;\n  }\n}\n@mixin tablet-xs{\n  @media(max-width:640px){\n    @content;\n  }\n}@mixin tablet{\n  @media(max-width:768px){\n    @content;\n  }\n}\n@mixin desktop{\n  @media(max-width:992px){\n    @content;\n  }\n}\n@mixin large-desktop{\n  @media(max-width:1200px){\n    @content;\n  }\n}\n","/*-----------------------------\n CSS INDEXING\n* --------------------------------------\n* 01.GLOBAL CSS STYLE\n* 02.TYPOGRAPHY CSS STYLE\n* 03.BUTTONS STYLE\n* 04.HOMEPAGE CSS STYLE\n    -LOGO CSS\n    -MENU CSS\n    -BACKGROUND\n* 05.FEATURES CSS STYLE\n* 06.SERVICE CSS STYLE\n* 07.ABOUT CSS STYLE\n* 08.PRICING CSS STYLE\n* 09.TESTIMONIAL STYLE\n* 10.LATEST BLOG CSS STYLE\n* 11.CONTACT CSS STYLE\n* 12.FOOTER CSS STYLE\n* ----------------------------------------\n*/\n\n// Fonts\n@import url(\"https://fonts.googleapis.com/css2?family=Plus Jakarta Sans:wght@400;500;600;700;800;900&display=swap\");\n\nhtml {\n  line-height: 1.15;\n  -webkit-text-size-adjust: 100%;\n  -ms-text-size-adjust: 100%;\n  // -ms-overflow-style: scrollbar;\n  -webkit-tap-highlight-color: rgba(0, 0, 0, 0);\n  font-family: \"Plus Jakarta Sans\", sans-serif !important;\n  overflow-x: hidden;\n  box-sizing: border-box;\n}\n\nbody {\n  font-family: $secondary-font;\n  font-size: 15px;\n  line-height: 1.75;\n  margin: 0;\n  text-align: left;\n  background-color: #fff;\n  font-weight: 400;\n  color: $black-light;\n}\n\n/*--------------------\n TYPOGRAPHY\n-----------------*/\n\n.h1,\n.h2,\n.h3,\n.h4,\n.h5,\n.h6,\nh1,\nh2,\nh3,\nh4,\nh5,\nh6 {\n  font-family: $primary-font;\n  font-weight: 700;\n  line-height: 1.35;\n  margin-bottom: 0.5rem;\n  color: $black;\n}\n\n.h1,\nh1 {\n  font-size: 2.125rem;\n  line-height: 40px;\n}\n\n.h2,\nh2 {\n  font-size: 1.625rem;\n}\n\n.h3,\nh3 {\n  font-size: 1.375rem;\n}\n\n.h4,\nh4 {\n  font-size: 1.125rem;\n}\n\n.h5,\nh5 {\n  font-size: 0.9375rem;\n}\n\n.h6,\nh6 {\n  font-size: 0.75rem;\n}\n\n.lead {\n  font-size: 1.0625rem;\n  font-weight: 300;\n}\n\n.font-weight-500 {\n  font-weight: 500 !important;\n}\n\n.section-title {\n  font-family: $secondary-font;\n  font-size: 43px;\n  font-weight: 700;\n  text-transform: capitalize;\n  margin-bottom: 15px;\n}\n\n.bg-grey {\n  background: $secondary-color;\n}\n\n.text-primary {\n  color: $primary-color !important;\n  background: $secondary-color;\n}\n","/*=== MEDIA QUERY ===*/\n/*-----------------------------\n CSS INDEXING\n* --------------------------------------\n* 01.GLOBAL CSS STYLE\n* 02.TYPOGRAPHY CSS STYLE\n* 03.BUTTONS STYLE\n* 04.HOMEPAGE CSS STYLE\n    -LOGO CSS\n    -MENU CSS\n    -BACKGROUND\n* 05.FEATURES CSS STYLE\n* 06.SERVICE CSS STYLE\n* 07.ABOUT CSS STYLE\n* 08.PRICING CSS STYLE\n* 09.TESTIMONIAL STYLE\n* 10.LATEST BLOG CSS STYLE\n* 11.CONTACT CSS STYLE\n* 12.FOOTER CSS STYLE\n* ----------------------------------------\n*/\n@import url(\"https://fonts.googleapis.com/css2?family=Plus Jakarta Sans:wght@400;500;600;700;800;900&display=swap\");\nhtml {\n  line-height: 1.15;\n  -webkit-text-size-adjust: 100%;\n  -ms-text-size-adjust: 100%;\n  -webkit-tap-highlight-color: rgba(0, 0, 0, 0);\n  font-family: \"Plus Jakarta Sans\", sans-serif !important;\n  overflow-x: hidden;\n  box-sizing: border-box;\n}\n\nbody {\n  font-family: \"Plus Jakarta Sans\", sans-serif;\n  font-size: 15px;\n  line-height: 1.75;\n  margin: 0;\n  text-align: left;\n  background-color: #fff;\n  font-weight: 400;\n  color: #6c757d;\n}\n\n/*--------------------\n TYPOGRAPHY\n-----------------*/\n.h1,\n.h2,\n.h3,\n.h4,\n.h5,\n.h6,\nh1,\nh2,\nh3,\nh4,\nh5,\nh6 {\n  font-family: \"Plus Jakarta Sans\", sans-serif;\n  font-weight: 700;\n  line-height: 1.35;\n  margin-bottom: 0.5rem;\n  color: #212529;\n}\n\n.h1,\nh1 {\n  font-size: 2.125rem;\n  line-height: 40px;\n}\n\n.h2,\nh2 {\n  font-size: 1.625rem;\n}\n\n.h3,\nh3 {\n  font-size: 1.375rem;\n}\n\n.h4,\nh4 {\n  font-size: 1.125rem;\n}\n\n.h5,\nh5 {\n  font-size: 0.9375rem;\n}\n\n.h6,\nh6 {\n  font-size: 0.75rem;\n}\n\n.lead {\n  font-size: 1.0625rem;\n  font-weight: 300;\n}\n\n.font-weight-500 {\n  font-weight: 500 !important;\n}\n\n.section-title {\n  font-family: \"Plus Jakarta Sans\", sans-serif;\n  font-size: 43px;\n  font-weight: 700;\n  text-transform: capitalize;\n  margin-bottom: 15px;\n}\n\n.bg-grey {\n  background: #F4F7FC;\n}\n\n.text-primary {\n  color: #21c87a !important;\n  background: #F4F7FC;\n}\n\n/*--------------------\nCommon Styles\n-----------------*/\n:root {\n  --primary-color: #30ab89;\n}\n\nhtml {\n  scroll-behavior: smooth;\n}\n\nimg {\n  vertical-align: middle;\n  border-style: none;\n}\n\n.img-thumbnail {\n  padding: 0.25rem;\n  border: 1px solid #dee2e6;\n  background-color: #fff;\n}\n\n.navbar-nav .dropdown-toggle::after {\n  display: none;\n}\n\n.section {\n  position: relative;\n  padding: 8.125rem 0;\n}\n\n@media (min-width: 768px) {\n  .section {\n    padding: 4.5rem 0;\n  }\n}\n.section-top {\n  padding-top: 8.125rem;\n}\n\n.section-bottom {\n  padding-bottom: 8.125rem;\n}\n\n@media (min-width: 768px) {\n  .section-top {\n    padding-top: 10.3125rem;\n  }\n}\n.bg-grey {\n  background: #f4f7fc;\n}\n\n/*-------------------\n  BUTTONS STYLE\n----------------=----*/\n.btn {\n  font-size: 0.6875rem;\n  font-weight: 700;\n  position: relative;\n  text-transform: uppercase;\n  padding: 1rem 2.4rem;\n  border: 0.1rem solid transparent;\n  transition: all 0.2s ease-in-out;\n  letter-spacing: 0.5px;\n}\n\n.btn-primary-border {\n  border-radius: 8px;\n  border: 3px solid #30ab89;\n  font-size: 0.875rem;\n}\n\n.btn-circle {\n  display: inline-flex;\n  width: 4.20313rem !important;\n  height: 4.20313rem !important;\n  padding: 0 !important;\n  border-radius: 50%;\n  align-items: center;\n  justify-content: center;\n}\n\n.btn-outline-dark {\n  border: 1px solid #222;\n}\n\n.btn-white {\n  background: #fff;\n  color: #212529;\n}\n\n.btn-trans-white {\n  border: 1px solid #fff;\n  color: #fff;\n}\n.btn-trans-white:hover {\n  color: #fff;\n  opacity: 0.5;\n}\n\n.btn-outline-dark:hover {\n  background: #222 !important;\n  color: #fff !important;\n}\n\n.btn.btn-link {\n  color: #212529;\n}\n\n.btn:focus {\n  box-shadow: none !important;\n}\n\n.btn-circled {\n  border-radius: 75px;\n}\n\n.bg-primary,\n.btn-primary,\n.btn-white:hover {\n  background: #21c87a !important;\n  border-color: #21c87a !important;\n  color: #fff;\n}\n\n.bg-dark,\n.btn-primary:hover {\n  background: #232323 !important;\n  border-color: #232323 !important;\n  color: #fff;\n}\n\n.shadow-sm-2 {\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n}\n\n/*------------------------\n BACKGROUND\n----------------------------*/\n.bg-cover {\n  background-repeat: no-repeat;\n  background-position: 50%;\n  background-size: cover;\n}\n\n.bg-cover,\n.bg-overlay,\n.bg-overlay:before {\n  position: absolute;\n  top: 0;\n  right: 0;\n  bottom: 0;\n  left: 0;\n}\n\n.bg-overlay:before {\n  content: \"\";\n  opacity: 0.55;\n  backgrou