ges/banner/service.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-about {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/about.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-pricing {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/img2.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-project {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/p-4.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-banner-content h1 {\n  color: #fff;\n  text-align: center;\n  font-size: 32px;\n  max-width: 500px;\n  margin: auto;\n}\n@media (max-width: 767px) {\n  .page-banner-content h1 {\n    font-size: 28px;\n  }\n}\n@media (max-width: 565px) {\n  .page-banner-content h1 {\n    font-size: 24px;\n  }\n}\n\n.page-banner-content p {\n  color: #21c87a;\n  font-weight: 600;\n}\n\n.meeting-button-wrapper {\n  display: flex;\n  gap: 1rem;\n  justify-content: center;\n}\n@media (max-width: 565px) {\n  .meeting-button-wrapper {\n    flex-direction: column;\n  }\n}\n.meeting-button-wrapper button,\n.meeting-button-wrapper a {\n  border: 0px;\n  font-weight: bold;\n  border-radius: 12px;\n  padding: 8px 12px;\n  background-color: white;\n  color: black;\n}\n.meeting-button-wrapper .filled-button {\n  background-color: #21c87a;\n  color: white;\n}\n\n.form-control {\n  border-radius: 0px;\n  height: 45px;\n}\n\n/*-------------------\n   MENU\n----------------------*/\n.navbar-toggler-icon {\n  display: inline-block;\n  width: 1.5em;\n  height: 1.5em;\n  content: \"\";\n  vertical-align: middle;\n  background: no-repeat 50%;\n  background-size: 100% 100%;\n}\n\n.navbar-dark .navbar-toggler {\n  color: #fff;\n  border-color: rgba(255, 255, 255, 0.1);\n  padding: 1