n    float: left !important;\n    width: 100%;\n    margin: 0;\n  }\n}\n.has-dropdown .dropdown-menu a {\n  font-weight: normal;\n  color: #808080;\n  padding: 10px 20px;\n  -webkit-transition: all 0.3s ease;\n  -moz-transition: all 0.3s ease;\n  -ms-transition: all 0.3s ease;\n  -o-transition: all 0.3s ease;\n  transition: all 0.3s ease;\n  border-bottom: 1px solid #eee;\n  border-radius: 4px;\n}\n.has-dropdown .dropdown-menu a:focus, .has-dropdown .dropdown-menu a:hover {\n  background: #21c87a;\n  color: #fff;\n}\n\n.dropleft .dropdown-menu,\n.dropright .dropdown-menu {\n  margin: 0;\n}\n\n.dropleft .dropdown-toggle::before,\n.dropright .dropdown-toggle::after {\n  font-weight: bold;\n  font-family: \"Font Awesome 5 Free\";\n  border: 0;\n  font-size: 10px;\n  vertical-align: 1px;\n}\n\n.dropleft .dropdown-toggle::before {\n  content: \"\\f053\";\n  margin-right: 7px;\n}\n\n.dropright .dropdown-toggle::after {\n  content: \"\\f054\";\n  margin-left: 7px;\n}\n\n.dropdown-item {\n  padding: 0.6rem 1.4rem;\n  text-transform: uppercase;\n  font-size: 12px;\n  font-weight: 700;\n}\n\n.dropdown-submenu:hover > .dropdown-item,\n.dropdown-item:hover {\n  background: #101010;\n  color: #fff !important;\n}\n\n.dropdown-item.active {\n  text-decoration: underline;\n  background-color: transparent;\n  color: inherit;\n}\n\n.dropdown-submenu.active > .dropdown-toggle {\n  text-decoration: underline;\n  color: inherit;\n}\n\nul.dropdown-menu li {\n  padding-left: 0px !important;\n}\n\n@media (min-width: 992px) {\n  .dropdown-menu {\n    transition: all 0.2s ease-in, visibility 0s linear 0.2s, transform 0.2s linear;\n    display: block;\n    visibility: hidden;\n    opacity: 0;\n    min-width: 200px;\n    transform: translateY(15px);\n  }\n  .dropdown:hover > .dropdown-menu {\n    visibility: visible;\n    transition: all 0.35s ease 0s;\n    opacity: 1;\n    transform: translateY(0);\n  }\n}\n.pt-60px {\n  padding-top: 60px !important;\n}\n\n@media (max-width: 992px) {\n  .position-md-sticky {\n    position: sticky !important;\n  }\n}\n/*----------------------\n BANNER STYLE\n-----------------------*/\n.py-7 {\n  padding: 7.5rem 0;\n}\n\n.py-4 {\n  padding: 4.5rem 0;\n}\n\n.py-8 {\n  padding: 8.5rem 0;\n}\n\n.main-banner h5 {\n  margin-bottom: 20px;\n}\n.main-banner h1.display-4 {\n  line-height: 65px;\n}\n\n.main-banner p.lead,\n.banner-content p.lead {\n  margin-bottom: 2.5rem !important;\n}\n\n/*-------------------------\n HOME -2\n-----------------------------*/\n#banner {\n  position: relative;\n  background: url(\"/images/bg/banner_bg.jpg\") no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.banner-content {\n  padding: 150px 0px;\n  padding-right: 30px;\n}\n.banner-content p {\n  color: #eee;\n  padding-right: 80px;\n  margin-bottom: 30px !important;\n}\n.banner-content .display-4 {\n  color: #fff;\n  font-weight: 600;\n}\n\n#banner .overlay {\n  opacity: 0.7;\n}\n\n.banner-contact-form {\n  padding: 45px 40px;\n  margin-top: 30px;\n}\n.banner-contact-form .form-control {\n  border-radius: 0px;\n  height: 45px;\n}\n.banner-contact-form textarea.form-control {\n  height: auto;\n}\n\n.transform-y-10 {\n  transform: translateY(2%);\n}\n\n.slick-dots {\n  position: absolute;\n  display: flex;\n  justify-content: center;\n  bottom: 0%;\n  left: -32px;\n}\n@media (max-width: 1200px) {\n  .slick-dots {\n    left: -35px;\n  }\n}\n@media (max-width: 992px) {\n  .slick-dots {\n    bottom: 4%;\n    left: auto;\n  }\n}\n@media (max-width: 640px) {\n  .slick-dots {\n    bottom: 95%;\n  }\n}\n@media (max-width: 768px) {\n  .slick-dots {\n    bottom: 4%;\n    padding-left: 0;\n  }\n}\n\n.slick-dots li {\n  width: auto;\n  height: auto;\n  margin-top: 10px;\n}\n@media (min-width: 992px) {\n  .slick-dots li {\n    display: block;\n  }\n}\n\n.bg-home .slick-carousel {\n  height: 55vh;\n  margin-top: 2rem;\n}\n@media (max-width: 400px) {\n  .bg-home .slick-carousel {\n    height: 60vh;\n  }\n}\n\n.bg-home .slick-dots {\n  gap: 12px;\n}\n\n.bg-home .slick-dots li a {\n  gap: 8px;\n}\n\n.slick-dots li svg:nth-child(1) {\n  display: block;\n}\n\n.slick-dots li svg:nth-child(2) {\n  display: none;\n}\n\n.slick-dots li.slick-active svg:nth-child(1) {\n  display: none;\n}\n\n.slick-dots li span {\n  font-weight: 700;\n  color: #707070;\n}\n@media (max-width: 400px) {\n  .slick-dots li span {\n    font-size: 12px;\n  }\n}\n\n.slick-dots li.slick-active span {\n  color: white;\n  font-size: 14px;\n}\n\n.slick-dots li.slick-active svg:nth-child(2) {\n  display: block;\n}\n\n.slick-carousel {\n  height: auto;\n}\n\n.slick-carousel {\n  width: 100%;\n}\n\n.text-primary {\n  color: #30ab89 !important;\n}\n\n.slider-container {\n  z-index: 10000;\n  position: relative;\n  width: 100%;\n  display: flex;\n  flex-direction: row;\n  align-items: center;\n  justify-content: space-between;\n  box-sizing: border-box;\n  height: fit-content;\n}\n@media (max-width: 992px) {\n  .slider-container {\n    padding: 0 20px;\n    flex-direction: column;\n    justify-content: center;\n    align-items: center;\n    height: 69vh;\n  }\n}\n.slider-container .text-primary {\n  background: none;\n}\n\n.slider-typo {\n  flex: 1;\n  width: 100%;\n  display: flex;\n  max-width: 800px;\n}\n@media (max-width: 992px) {\n  .slider-typo {\n    text-align: center;\n    justify-content: center;\n  }\n}\n\n.img-cont {\n  display: flex;\n  justify-content: flex-end;\n  align-items: flex-end;\n  margin-top: auto;\n}\n@media (max-width: 768px) {\n  .img-cont {\n    justify-content: center;\n  }\n}\n\n#plantImg {\n  filter: grayscale(100%);\n}\n\n.slider-img {\n  width: 100%;\n  height: auto;\n  transform: translateY(5%);\n  filter: grayscale(100%);\n}\n.slider-img img {\n  width: 100%;\n}\n\nsection.slick-dotted.slick-slider {\n  margin-bottom: 0;\n}\n\n@media (min-width: 992px) {\n  .carousel-cont {\n    padding-left: 10px;\n  }\n  .slider-img {\n    margin-right: 2rem;\n  }\n}\n@media (min-width: 768px) and (max-width: 992px) {\n  .slider-container {\n    height: 75vh;\n  }\n  .slider-img {\n    margin-right: 1rem;\n  }\n}\n.stack {\n  display: grid;\n  grid-template-columns: 1fr;\n}\n\n.stack span {\n  font-weight: bold;\n  grid-row-start: 1;\n  grid-column-start: 1;\n  --stack-height: calc(100% / var(--stacks) - 1px);\n  --inverse-index: calc(calc(var(--stacks) - 1) - var(--index));\n  --clip-top: calc(var(--stack-height) * var(--index));\n  --clip-bottom: calc(var(--stack-height) * var(--inverse-index));\n  clip-path: inset(var(--clip-top) 0 var(--clip-bottom) 0);\n  animation: stack 340ms cubic-bezier(0.46, 0.29, 0, 1.24) 1 backwards calc(var(--index) * 120ms), glitch 2s ease infinite 2s alternate-reverse;\n}\n\n.stack span:nth-child(odd) {\n  --glitch-translate: 8px;\n}\n\n.stack span:nth-child(even) {\n  --glitch-translate: -8px;\n}\n\n@keyframes stack {\n  0% {\n    opacity: 0;\n    transform: translateX(-50%);\n    text-shadow: -2px 3px 0 red, 2px -3px 0 blue;\n  }\n  60% {\n    opacity: 0.5;\n    transform: translateX(50%);\n  }\n  80% {\n    transform: none;\n    opacity: 1;\n    text-shadow: 2px -3px 0 red, -2px 3px 0 blue;\n  }\n  100% {\n    text-shadow: none;\n  }\n}\n@keyframes glitch {\n  0% {\n    text-shadow: -2px 3px 0 red, 2px -3px 0 blue;\n    transform: translate(var(--glitch-translate));\n  }\n  2% {\n    text-shadow: 2px -3px 0 red, -2px 3px 0 blue;\n  }\n  4%, 100% {\n    text-shadow: none;\n    transform: none;\n  }\n}\n.snowflake {\n  position: absolute;\n  bottom: 0;\n  background: white;\n  border-radius: 50%;\n  opacity: 0;\n  transform: translateY(0);\n  animation: snowfall 5s ease-in-out infinite;\n}\n\n@keyframes snowfall {\n  0% {\n    opacity: 0;\n    transform: translateY(0);\n  }\n  20% {\n    opacity: 1;\n  }\n  80% {\n    opacity: 1;\n  }\n  100% {\n    opacity: 0;\n    transform: translateY(-100vh);\n  }\n}\n#banner-3 {\n  position: relative;\n  background: url(\"../images/banner/banner.jpg\") no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n#banner-4 {\n  position: relative;\n  background: url(\"../images/banner/banner-2.jpg\") no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.seed-stats {\n  background: url(../../images/stats/stats-bg.png);\n  background-size: cover;\n  background-position: center;\n  background-repeat: no-repeat;\n}\n\n.default-section-heading {\n  color: #2C2C2C;\n  font-size: 32px;\n  font-weight: 600;\n}\n\n.default-section-heading span {\n  color: #30AB89;\n}\n\n.default-text-para {\n  color: #2C2C2C;\n  font-style: normal;\n  line-height: normal;\n}\n\n.seed-stats .stats-count .count {\n  color: #2C2C2C;\n  font-size: 44px;\n  font-weight: 800;\n}\n@media (max-width: 767px) {\n  .seed-stats .stats-count .count {\n    font-size: 32px;\n  }\n}\n\n.seed-stats .stats-count p {\n  color: #2C2C2C;\n  font-size: 12px;\n  font-weight: 500;\n}\n\n/*----------------------\n FEATURE STYLE\n-----------------------*/\n.img-icon-block {\n  position: relative;\n}\n.img-icon-block:before {\n  position: absolute;\n  content: \"\";\n  top: -2rem;\n  background: #A5EBD7;\n  opacity: 1;\n  width: 84px;\n  left: 5rem;\n  height: 84px;\n  border-radius: 50%;\n  z-index: 1;\n}\n.img-icon-block img {\n  font-size: 58px;\n  z-index: 3 !important;\n  color: #333;\n  position: relative;\n  width: 48px;\n  height: 48px;\n}\n\n/*--------------------------\nABOUT-2\n---------------------------*/\n#about .img-block {\n  position: relative;\n  -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n}\n#about .img-block img {\n  border: 5px solid #21c87a;\n}\n\n.pt-6 {\n  padding-top: 4.5rem;\n}\n\n.img-icon i {\n  font-size: 60px;\n}\n\n#feature .head-title-text {\n  color: var(--text-color, #2C2C2C);\n  text-align: center;\n  font-family: Plus Jakarta Sans;\n  font-size: 20px;\n  font-style: normal;\n  font-weight: 500;\n  line-height: normal;\n  max-width: 600px;\n  display: inline-block;\n}\n\n#feature .head-title-text span {\n  color: #30AB89;\n  font-weight: 700;\n}\n\n@media screen and (max-width: 991px) {\n  .img-icon-block:before {\n    width: 70px;\n    height: 70px;\n  }\n  .img-icon-block img {\n    width: 50px;\n    height: 50px;\n  }\n  #feature .head-title-text {\n    font-size: 20px;\n  }\n}\n/*----------------------\n SERVICE\n-----------------------*/\n.service-container {\n  margin: auto;\n  max-width: 1540px;\n  margin: 80px auto;\n}\n@media (max-width: 1154px) {\n  .service-container {\n    margin: 50px auto;\n  }\n}\n\nh5.subtitle {\n  color: #21c87a;\n  margin-bottom: 10px;\n  font-weight: 300;\n}\n\n#service-subheading {\n  color: #2C2C2C;\n  text-align: center;\n  font-size: 16px;\n  font-style: normal;\n  font-weight: 400;\n  line-height: 1.5;\n}\n@media (max-width: 1154px) {\n  #service-subheading {\n    font-size: 14px;\n  }\n}\n\n#service-heading {\n  margin-bottom: 14px !important;\n  font-size: 32px;\n  line-height: 1.25;\n}\n@media (max-width: 1154px) {\n  #service-heading {\n    font-size: 25px;\n  }\n}\n#service-heading span {\n  color: #30AB89;\n}\n\n.service-heading {\n  margin-bottom: 50px !important;\n}\n\n.service-images {\n  margin-bottom: -200px;\n  border: 10px solid #fff;\n}\n\n.service-content {\n  padding-top: 60px;\n  padding-left: 15px;\n}\n.service-content h1 {\n  margin-bottom: 20px;\n  margin-top: 15px;\n}\n\n.service-icon {\n  margin-right: 20px;\n  color: #fff;\n  font-size: 25px;\n  width: 50px;\n  height: 50px;\n  background: #A5EBD7;\n  text-align: center;\n  border-radius: 50%;\n  padding-top: 5px;\n}\n\n.service-block {\n  margin-bottom: 50px;\n}\n\n/*----------------------\n WEB SERVICES\n-----------------------*/\n#services-2 {\n  position: relative;\n  padding: 20px;\n  -webkit-background-size: cover;\n  background-size: cover;\n  background-color: #FAFAFA;\n  color: #2C2C2C;\n}\n\n.service-blocks {\n  display: grid;\n  grid-template-columns: 1fr 1fr 1fr;\n  gap: 1rem;\n}\n@media (max-width: 1154px) {\n  .service-blocks {\n    grid-template-columns: 1fr 1fr;\n  }\n}\n@media (max-width: 800px) {\n  .service-blocks {\n    grid-template-columns: 1fr;\n  }\n}\n\n.key-features-blocks {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 1rem;\n}\n@media (max-width: 1154px) {\n  .key-features-blocks {\n    grid-template-columns: 1fr;\n  }\n}\n\n.service-blocks-4 {\n  display: grid;\n  grid-template-columns: 1fr 1fr 1fr 1fr;\n  gap: 1rem;\n}\n@media (max-width: 1154px) {\n  .service-blocks-4 {\n    grid-template-columns: 1fr 1fr 1fr;\n  }\n}\n@media (max-width: 800px) {\n  .service-blocks-4 {\n    grid-template-columns: 1fr;\n  }\n}\n\n.web-service-block {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n  padding: 1.5rem;\n  transition: 0.3s;\n  border-radius: 5px;\n  cursor: pointer;\n}\n.web-service-block .image-container {\n  height: 4rem;\n}\n.web-service-block .image-container-black {\n  height: 4rem;\n}\n.web-service-block .image-container-black img {\n  height: 100%;\n}\n.web-service-block .image-container img {\n  height: 100%;\n  filter: brightness(1) invert(1);\n}\n.web-service-block h3 {\n  font-size: 25px;\n  margin: 0;\n  transition: 0.3s;\n  color: #2C2C2C;\n}\n.web-service-block p {\n  font-size: 15px;\n  font-weight: 400;\n  transition: 0.3s;\n  color: #2C2C2C;\n  line-height: 1.5;\n}\n.web-service-block a {\n  color: #30AB89 !important;\n  font-size: 18px;\n  font-weight: 700;\n  cursor: pointer;\n  margin-top: auto;\n}\n\n.service-img {\n  margin-bottom: -200px !important;\n  border: 10px solid #fff;\n  margin: auto;\n}\n\n.why-choose-card {\n  border: solid 1px #dcdcdc;\n}\n\n.card-hover-effect {\n  transition: all 200ms;\n}\n\n.card-hover-effect:hover {\n  transform: scale(1.02);\n  box-shadow: 0px 0px 15px 0px rgba(32, 201, 150, 0.2352941176);\n}\n\n.how-it-works-card {\n  display: flex;\n  flex-direction: column;\n  gap: 1px;\n}\n.how-it-works-card p {\n  font-size: 16px;\n}\n\n/*----------------------\n PRoject\n-----------------------*/\n#projects-wrap {\n  position: relative;\n  background: url(\"../images/bg/banner_bg.jpg\") no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n#projects-wrap p.lead {\n  color: #a9a9a9 !important;\n}\n\n.overlay {\n  position: absolute;\n  left: 0;\n  top: 0;\n  width: 100%;\n  height: 100%;\n  background: rgba(0, 0, 0, 0.92);\n}\n\n.overlay.feature-overlay {\n  background-image: linear-gradient(30deg, rgba(121, 110, 255, 0.95) 0%, #30ab89 100%);\n  opacity: 0.9;\n}\n\n#projects {\n  margin-top: -60px;\n}\n\n.single-project img {\n  border-radius: 10px;\n}\n\n.project-content {\n  text-align: center;\n  padding: 40px 20px;\n  position: relative;\n}\n.project-content .btn {\n  padding: 0.7rem 1.7rem;\n  border-radius: 25px;\n}\n.project-content p {\n  margin-top: 20px;\n}\n.project-content h4 {\n  text-transform: capitalize;\n}\n\n.project-content-block {\n  padding: 70px 40px;\n  margin-left: -120px;\n  background: #f4f7fc;\n  position: absolute;\n  bottom: -70px;\n  border: 15px solid #fff;\n  -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n}\n.project-content-block h4 {\n  color: #21c87a;\n}\n.project-content-block p {\n  margin-top: 25px;\n}\n\n/*-------------------------\n PORTFOLIO-2\n---------------------------*/\n.single-work {\n  -webkit-transition: all 300ms ease-in-out;\n  -o-transition: all 300ms ease-in-out;\n  transition: all 300ms ease-in-out;\n}\n\n.overlay-content-block {\n  position: absolute;\n  content: \"\";\n  bottom: 20px;\n  width: 100%;\n  left: 30px;\n  padding: 30px 20px;\n  background: #fff;\n  opacity: 0;\n  visibility: hidden;\n  -webkit-transition: all 300ms ease-in-out;\n  -o-transition: all 300ms ease-in-out;\n  transition: all 300ms ease-in-out;\n  border-radius: 5px 0px 0px 5px;\n}\n.overlay-content-block .icon {\n  width: 50px;\n  height: 50px;\n  display: inline-block;\n  text-align: center;\n  padding-top: 12px;\n  border-radius: 100%;\n  position: absolute;\n  left: 30px;\n  top: -23px;\n  background: #21c87a;\n  color: #fff;\n}\n.overlay-content-block h4 {\n  margin-bottom: 0px;\n  margin-top: 10px;\n}\n\n.work-block {\n  position: relative;\n  border: 5px solid #fff;\n}\n.work-block img {\n  width: 100%;\n  border-radius: 10px;\n  box-shadow: 0px 2px 10px 0px rgba(0, 0, 0, 0.14);\n  object-fit: cover;\n  aspect-ratio: 4/3;\n}\n.work-block:hover .overlay-content-block {\n  opacity: 1;\n  visibility: visible;\n}\n\n.card-content {\n  padding: 0.7rem 0.5rem 0;\n}\n.card-content h4 {\n  color: var(--text-color, #2C2C2C);\n  font-size: 24px;\n  font-style: normal;\n  font-weight: 600;\n  line-height: normal;\n}\n.card-content p {\n  color: var(--text-color, #2C2C2C);\n  font-size: 14px;\n  font-style: normal;\n  font-weight: 400;\n  line-height: normal;\n}\n.card-content .link {\n  font-weight: 600;\n  color: #30AB89;\n}\n\n/* ==============================\n  SINGEL PROJECTS\n=============================*/\n.project-details-info {\n  margin: 40px 0px;\n}\n\n.info-block-2 {\n  float: left;\n  margin-right: 65px;\n  margin-bottom: 40px;\n}\n\n.project-info ul {\n  margin-top: 40px;\n}\n.project-info ul li {\n  margin-bottom: 30px;\n  padding-right: 20px;\n}\n\n.project-lg-images img {\n  width: 100%;\n}\n\n.alumni-description {\n  color: var(--text-color, #2c2c2c);\n  text-align: center;\n  font-size: 20px;\n  font-style: normal;\n  font-weight: 500;\n  line-height: normal;\n  color: #343a40;\n}\n.alumni-description span {\n  color: #30ab89;\n  font-weight: 700;\n}\n\n/*----------------------\n PROCESS\n-----------------------*/\nsection#process {\n  background-image: url(\"../../images/bg/Logo seed.png\");\n  background-repeat: no-repeat;\n  background-size: contain;\n  background-position: left;\n  min-height: 574px;\n}\n\n#alumni-container img {\n  filter: none;\n  margin: 30px auto;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n}\n#alumni-container p {\n  font-size: 18px;\n  margin: auto;\n  font-family: \"Plus Jakarta Sans\", sans-serif !important;\n}\n@media screen and (max-width: 991px) {\n  #alumni-container p {\n    font-size: 24px !important;\n  }\n}\n@media screen and (max-width: 767px) {\n  #alumni-container p {\n    font-size: 18px !important;\n  }\n}\n@media screen and (max-width: 575px) {\n  #alumni-container p {\n    font-size: 16px !important;\n  }\n}\n\n#bytecorpimg {\n  width: 45px;\n}\n\n#Foliologo {\n  width: 150px;\n}\n\n#nustlogo {\n  width: 170px;\n}\n\n#JafferLogo {\n  width: 120px;\n}\n\n.process-block {\n  margin: auto;\n  text-align: center;\n}\n.process-block img {\n  border-radius: 5px;\n  margin-bottom: 45px;\n}\n.process-block h3 {\n  margin-bottom: 15px;\n}\n\n.bottom-bar {\n  margin-top: 40px;\n  max-width: 860px;\n  display: flex;\n  flex-direction: row;\n  justify-content: space-between;\n  align-items: center;\n  margin: auto;\n  font-family: \"Plus Jakarta Sans\", sans-serif;\n}\n.bottom-bar h2 {\n  text-align: center;\n  color: var(--heading-color, #202020);\n  font-size: 48px;\n  font-style: normal;\n  font-weight: 800;\n  line-height: normal;\n}\n.bottom-bar p {\n  color: var(--text-color, #2c2c2c);\n  text-align: center;\n  font-size: 14px;\n  font-style: normal;\n  font-weight: 500;\n  line-height: normal;\n}\n.bottom-bar div {\n  margin-top: 24px;\n}\n\n#section-para {\n  font-size: 24px;\n  font-weight: 400;\n}\n#section-para span {\n  color: #2b9778;\n  font-weight: 700;\n}\n\n.earn-trust {\n  max-width: 479px;\n  color: var(--text-color, #2c2c2c);\n  text-align: center;\n  font-size: 20px;\n  font-style: normal;\n  font-weight: 500;\n  line-height: normal;\n}\n\n.earn-trust span {\n  color: var(--main-color-1, #30ab89);\n  font-size: 20px;\n  font-style: normal;\n  font-weight: 700;\n  line-height: normal;\n}\n\n.section-heading {\n  display: flex;\n  justify-content: center;\n}\n\n/*----------------------\n PRICING\n-----------------------*/\n.price-block {\n  margin: 20px 0px 30px;\n}\n.price-block h2 {\n  font-size: 80px;\n  font-weight: 700;\n  position: relative;\n  display: inline-block;\n}\n.price-block h2 small {\n  position: absolute;\n  top: 20px;\n  font-size: 16px;\n  left: -9px;\n}\n.price-block h6 {\n  font-size: 14px;\n  border-top: 1px solid #eee;\n  border-bottom: 1px solid #eee;\n  padding: 7px;\n  text-transform: capitalize;\n  width: 50%;\n  margin: 10px auto;\n}\n\n.price-features {\n  margin: 30px 0px 50px;\n}\n.price-features li {\n  font-size: 16px;\n  padding: 5px 0px;\n  position: relative;\n  padding-left: 30px;\n}\n.price-features li:before {\n  position: absolute;\n  content: \"\\f00c\";\n  font-family: \"Font Awesome 5 Free\";\n  left: 0px;\n  top: 5px;\n  color: #21c87a;\n  font-weight: 900;\n}\n\n.pricing-block .price-features li {\n  padding-left: 0px;\n}\n.pricing-block .price-features li:before {\n  display: none;\n}\n\n/*--------------------------\nPRICING-2\n---------------------------*/\n.pricing-box {\n  border: 1px solid #eee;\n  padding: 60px;\n  -webkit-transition: all 300ms ease-in-out;\n  -o-transition: all 300ms ease-in-out;\n  transition: all 300ms ease-in-out;\n}\n.pricing-box .price-block h2 span {\n  font-size: 12px;\n  font-weight: normal;\n  text-transform: capitalize;\n}\n.pricing-box:hover {\n  background: rgb(29, 28, 28);\n  border-color: rgb(29, 28, 28);\n}\n.pricing-box:hover .price-features li {\n  color: #eee;\n}\n.pricing-box:hover .price-block h2 {\n  color: #fff;\n}\n.pricing-box:hover h3 {\n  color: #fff;\n}\n.pricing-box:hover .btn {\n  background: #fff !important;\n  color: #000 !important;\n}\n\n/*----------------------\n BLOG SECTION\n-----------------------*/\n.blog-box {\n  position: relative;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  height: 100%;\n}\n.blog-box .blog-img-box img {\n  width: 100%;\n  border-radius: 10px;\n  box-shadow: 0px 2px 10px 0px rgba(0, 0, 0, 0.14);\n  object-fit: contain;\n  aspect-ratio: 16/11;\n  background-color: #101010;\n}\n\n.single-blog {\n  padding-top: 25px;\n  position: relative;\n  height: 100%;\n}\n\n.bg-light .single-blog {\n  padding: 40px;\n  text-align: center;\n  border-bottom: 1px solid #eee;\n}\n\n.blog-content {\n  display: flex;\n  flex-direction: column;\n  height: 100%;\n  flex-grow: 1;\n}\n.blog-content a h3 {\n  color: var(--text-color, #2c2c2c);\n  font-size: 20px;\n  font-style: normal;\n  font-weight: 600;\n  line-height: normal;\n}\n.blog-content p {\n  color: var(--text-color, #2C2C2C);\n  font-size: 14px;\n  font-style: normal;\n  font-weight: 400;\n  line-height: normal;\n}\n.blog-content .link {\n  font-weight: 500;\n  color: #30AB89;\n}\n\n/*------------------------------------\nSECTION TESTIMONIAL\n-------------------------------------*/\n#section-testimonial {\n  position: relative;\n  padding: 20px;\n  -webkit-background-size: cover;\n  background-size: cover;\n  background-color: #101010;\n}\n\n.mb25 {\n  margin-bottom: 25px;\n}\n\n.testimonial-container {\n  margin: auto;\n  max-width: 1540px;\n  margin: 80px auto;\n}\n@media (max-width: 1154px) {\n  .testimonial-container {\n    margin: 50px auto;\n  }\n}\n\n.test-inner {\n  display: flex;\n  padding: 24px;\n  flex-direction: column;\n  justify-content: center;\n  align-items: flex-start;\n  gap: 22px;\n  color: var(--white-color, #fafafa);\n  font-size: 14px;\n  font-style: normal;\n  font-weight: 400;\n  line-height: normal;\n  border-radius: 32px;\n  border: 2px solid var(--main-color-1, #30ab89);\n  min-height: 254px;\n  height: 300px;\n  width: 500px;\n}\n@media screen and (max-width: 1200px) {\n  .test-inner {\n    margin-bottom: 1rem;\n    height: 320px;\n    width: 420px;\n  }\n}\n@media screen and (max-width: 1000px) {\n  .test-inner {\n    margin-bottom: 1rem;\n    height: 350px;\n    width: 320px;\n  }\n}\n@media screen and (max-width: 900px) {\n  .test-inner {\n    margin-bottom: 1rem;\n    height: 350px;\n    width: 400px;\n  }\n}\n@media screen and (max-width: 500px) {\n  .test-inner {\n    margin-bottom: 1rem;\n    height: 380px;\n    width: 320px;\n  }\n}\n@media screen and (max-width: 370px) {\n  .test-inner {\n    margin-bottom: 1rem;\n    height: 400px;\n    width: 280px;\n  }\n}\n\n.test-author-thumb {\n  align-items: center;\n  gap: 1rem;\n}\n.test-author-thumb img {\n  width: 56px;\n  height: 56px;\n  border-radius: 100%;\n  padding: 5px;\n}\n\n#video-modal .test-author-thumb {\n  align-items: center;\n  gap: 1rem;\n}\n#video-modal .test-author-thumb .star-image {\n  width: 32px;\n  height: 32px;\n  border-radius: 100%;\n  padding: 5px;\n}\n\n.test-author-info {\n  gap: 0.25rem;\n}\n.test-author-info h4 {\n  color: var(--white-color, #fafafa);\n  font-size: 18px;\n  font-style: normal;\n  font-weight: 600;\n  line-height: normal;\n  margin: 0;\n}\n.test-author-info h6 {\n  color: var(--white-color, #fafafa);\n  font-size: 10px;\n  font-style: normal;\n  font-weight: 400;\n  line-height: normal;\n  margin: 0;\n}\n\n/*----------------------\n TETSIMONIAL-2\n-------------------------*/\n.testimonial .content img {\n  margin: 0 auto 30px;\n  border: 3px solid #fff;\n}\n\n.img-md {\n  width: 120px;\n  height: 120px;\n  border-radius: 100%;\n}\n\n.testimonals-slider .slick-dots {\n  display: flex !important;\n  justify-content: center;\n  left: 50%;\n  transform: translate(-55%, 0);\n  bottom: -50px !important;\n  top: auto;\n}\n\n.testimonial-next img,\n.testimonial-prev img {\n  filter: brightness(0) invert(1);\n}\n\n.thumbnail {\n  position: relative;\n  display: inline-block;\n  cursor: pointer;\n}\n\n.thumbnail::before {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  content: \"\";\n  background: linear-gradient(180deg, rgba(0, 0, 0, 0) 0%, rgb(48, 171, 137) 80%);\n  border-radius: 1.5rem;\n}\n\n.thumbnail img {\n  width: 100%;\n  height: auto;\n  border-radius: 1.5rem;\n}\n\n.thumbnail .client-info {\n  position: absolute;\n  display: flex;\n  bottom: 20%;\n  left: 10%;\n  z-index: 100;\n  width: 100%;\n  height: 20px;\n  display: flex;\n  align-items: center;\n  gap: 1rem;\n}\n.thumbnail .client-info h4 {\n  color: black;\n  font-weight: 800;\n  font-size: 20px;\n}\n\n.thumbnail .client-info p {\n  margin-bottom: 0px;\n}\n\n.play-button {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  cursor: pointer;\n  width: 40px;\n  height: 40px;\n  border-radius: 200px;\n  background-color: #30ab89;\n}\n\n.play-button:hover {\n  background-color: #095c44;\n}\n\n/* Modal styling */\n.modal {\n  display: none;\n  transition: all 300ms ease;\n  position: fixed;\n  z-index: 1000;\n  left: 0;\n  top: 5%;\n  width: 100%;\n  height: 100%;\n  overflow: hidden;\n  background-color: rgba(0, 0, 0, 0.7);\n}\n\n.modal-content {\n  position: absolute;\n  left: 50%;\n  top: 50%;\n  transform: translate(-50%, -50%);\n  padding: 32px;\n  width: 80%;\n  max-width: 600px;\n  border: 2px solid #1f6652;\n  border-bottom: 2px solid #288168;\n  background: linear-gradient(#000 90%, #214d40 100%);\n  border-radius: 8px;\n}\n\n.close {\n  position: absolute;\n  top: 0px;\n  right: 10px;\n  font-size: 2em;\n  color: white;\n  cursor: pointer;\n}\n\n.close:hover {\n  color: white;\n}\n\n#progress {\n  background-color: orange;\n}\n\n.player {\n  position: relative;\n  max-width: 750px;\n  margin: 20px auto;\n  box-shadow: 0 0 20px rgba(0, 0, 0, 0.2);\n}\n\n.viewer {\n  width: 100%;\n  height: auto;\n  border-radius: 5px;\n}\n\n.player__controls {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 10px;\n  background: #000;\n}\n\n.progress {\n  flex: 1;\n  height: 5px;\n  background: #ccc;\n  cursor: pointer;\n  margin-right: 10px;\n  position: relative;\n}\n\n.progress__filled {\n  width: 0;\n  height: 100%;\n  background: #30ab89;\n  transition: width 0.1s;\n}\n\n.player__button {\n  background: none;\n  transition: all 200ms ease;\n  border: 0;\n  margin-right: 5px;\n  color: #30ab89;\n  border-radius: 5px;\n  background-color: rgba(48, 171, 136, 0.2117647059);\n  font-size: 20px;\n  cursor: pointer;\n}\n\n.player__button:hover {\n  background: rgba(48, 171, 136, 0.4039215686);\n  color: #3bc59e;\n  font-size: 20px;\n  cursor: pointer;\n}\n\n::-webkit-scrollbar {\n  width: 10px;\n  transition: all 200ms ease-in;\n}\n\n/* Track */\n::-webkit-scrollbar-track {\n  background: #0f1614;\n  padding-block: 5px;\n  border-radius: 100px;\n}\n\n/* Handle */\n::-webkit-scrollbar-thumb {\n  /* background: #888; */\n  background: #30ab89;\n  border-radius: 100px;\n}\n\n/* Handle on hover */\n::-webkit-scrollbar-thumb:hover {\n  background: #1d745b;\n  width: 17px;\n}\n\n/*---------------------------\nCONTACT PAGE\n-----------------------------*/\n#contact-info {\n  padding-top: 90px;\n}\n\n.contact-info-block {\n  border: 1px solid #eee;\n  padding: 40px 20px;\n  border-radius: 5px;\n}\n.contact-info-block h4 {\n  margin-bottom: 0px;\n}\n.contact-info-block i {\n  font-size: 40px;\n  margin-bottom: 20px;\n  display: block;\n  color: #21c87a;\n}\n\n.form-control:focus,\n.form-control:hover {\n  border-color: #21c87a;\n  box-shadow: none;\n}\n\na.lead {\n  color: inherit;\n}\n\n/* --------------\n    MAP\n-----------------*/\n#map {\n  height: 400px;\n  width: 100%;\n}\n\n.form-left-details .primary-heading {\n  font-size: 24px;\n  font-weight: 600;\n}\n.form-left-details .seconday-heading {\n  font-size: 16px;\n  font-weight: 500;\n  color: #21c87a;\n  margin-bottom: 8px;\n}\n.form-left-details .unordered-check-list {\n  padding-left: 2.25rem;\n  list-style: none;\n}\n.form-left-details .unordered-check-list li {\n  position: relative;\n  padding: 0.62rem 0;\n}\n.form-left-details .unordered-check-list li:before {\n  content: \"\";\n  position: absolute;\n  left: -2.25rem;\n  top: 0.9375rem;\n  width: 1.25rem;\n  height: 1.25rem;\n  background-image: url(../../images/icon/correct-icon.svg);\n  background-repeat: no-repeat;\n}\n\n.contact-section-title {\n  font-size: 28px;\n  max-width: 800px;\n  margin-bottom: 3rem !important;\n  margin: auto;\n  display: block;\n  text-align: center;\n  margin: auto;\n}\n@media (max-width: 575px) {\n  .contact-section-title {\n    font-size: 24px;\n    margin-bottom: 2rem !important;\n  }\n}\n@media (max-width: 400px) {\n  .contact-section-title {\n    font-size: 20px;\n    margin-bottom: 1rem !important;\n  }\n}\n\n.contact_form {\n  padding: 3rem 2rem;\n  background: #fff;\n  box-shadow: 0px 0px 5px #ddd;\n  border-radius: 0.5rem;\n}\n\n/*----------------------\n FOOTER\n-----------------------*/\n#footer {\n  padding: 70px 0px 30px;\n  position: relative;\n}\n#footer .footer-brand .logo {\n  max-width: 20rem;\n}\n#footer .footer-brand {\n  font-size: 30px;\n}\n#footer .footer-links {\n  padding-left: 0;\n  list-style-type: none;\n}\n\n#footer {\n  background: url(\"../images/bg/10.jpg\");\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.footer-overlay {\n  background: #111;\n  opacity: 0.94;\n}\n\n.footer-widget {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n}\n\n.social-icons {\n  margin-top: 14px;\n}\n.social-icons img {\n  width: 20px;\n  margin-right: 1rem;\n}\n\n.primary-btn {\n  padding: 10px 28px;\n  border-radius: 24px;\n  background-color: #30ab89;\n  color: #fff;\n  font-size: 14px;\n  font-weight: 500;\n  line-height: 17px;\n  transition: 0.3s ease-in-out;\n  border: 2px solid #30ab89 !important;\n  position: relative;\n}\n.primary-btn .nav-link {\n  padding: 0px !important;\n}\n\n.primary-btn::after {\n  position: absolute;\n  width: 12px;\n  height: 14px;\n  right: -30px;\n  top: 50%;\n  transform: translate(0, -55%);\n  background: url(/images/icon/right-arrow.svg);\n  content: \"\";\n  transition: 0.3s ease-in-out;\n  opacity: 0;\n  filter: brightness(0) invert(1);\n}\n\n.primary-btn:hover {\n  background-color: transparent !important;\n  padding-left: 20px;\n  padding-right: 36px;\n  color: #30ab89 !important;\n}\n.primary-btn:hover .nav-link {\n  color: #30ab89 !important;\n}\n\n.primary-btn:hover::after {\