xt-decoration: none;\n}\n\n.what-we-offer .card-header {\n  padding: 0;\n  border: 0px;\n  background: transparent;\n}\n\n.what-we-offer .card {\n  border: 0;\n  border-bottom: 1px solid #c8c8c8 !important;\n  border-radius: 0px !important;\n}\n\n.what-we-offer .card .card-body {\n  padding: 0px 0px 24px;\n}\n\n.process-steps {\n  background-color: #f1f1f1;\n  overflow: hidden;\n}\n\n.section--full,\n.section--vertical {\n  min-height: 50vh;\n  position: relative;\n}\n\n.block-list {\n  white-space: nowrap;\n  padding-left: 100px !important;\n}\n\n.block-list__item {\n  width: 415px;\n  margin-right: 70px;\n  display: inline-block;\n  white-space: normal;\n}\n\n.block-list__item-inner {\n  width: 100%;\n  height: 100%;\n  position: relative;\n}\n\n.block-list__item-inner::before {\n  counter-increment: element;\n  content: counter(element);\n  position: absolute;\n  left: -55px;\n  width: 35px;\n  height: 35px;\n  top: 50%;\n  transform: translateY(-55%);\n  border: 1px solid #2C2C2C;\n  border-radius: 50%;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  font-size: 20px;\n  font-style: normal;\n  font-weight: 600;\n  line-height: 35px;\n  color: #2C2C2C;\n}\n\n.block-list__item:first-child {\n  margin-left: 0;\n}\n\n#third {\n  background: #f5f5f5;\n}\n\n.scrollend {\n  transform: translateX(-1500px);\n}\n\n.block-list {\n  counter-reset: element;\n  list-style: none;\n}\n\n.scroll-content .mobile {\n  display: none;\n}\n\n@media (max-width: 767px) {\n  .section--vertical.desktop {\n    display: none;\n  }\n  .block-list__item-inner::before {\n    display: none;\n  }\n  .scroll-content .mobile {\n    display: block;\n  }\n}\n.seed-contact-form #service-heading {\n  margin-bottom: 2rem !important;\n  text-align: center;\n}\n\n.smallform {\n  max-width: 800px;\n  border: 1px solid #666666;\n  min-height: 300x;\n  margin: auto;\n  border-radius: 1rem;\n}\n.smallform .chat-messages {\n  padding: 2rem;\n  display: flex;\n  flex-direction: column;\n  gap: 1.5rem;\n}\n.smallform .chat-messages .chat-message {\n  align-items: center;\n  gap: 1rem;\n}\n.smallform .chat-messages .chat-message img {\n  flex-shrink: 0;\n  height: 32px;\n}\n.smallform .chat-messages .chat-message p {\n  font-size: 16px;\n  font-weight: 500;\n  margin-bottom: 0px;\n}\n.smallform .input-container {\n  border-top: 1px solid #666666;\n  padding: 1rem 2rem;\n}\n.smallform .input-container div {\n  gap: 1rem;\n}\n.smallform .input-container textarea {\n  display: block;\n  max-width: 100%;\n  overflow: hidden;\n  border-radius: 32px;\n  width: 100%;\n  border: 1px solid #222222;\n  padding: 8px 12px;\n}","$light: #fff;\n$primary-color: #30AB89;\n$primary-colors: #30AB89;\n$primary-color: #21c87a;\n$primary-background-gradient: linear-gradient(180deg, #61E1BE 0%, rgba(118, 211, 246, 0.25) 100%);\n$secondary-color: #F4F7FC;\n$black-text: #2C2C2C;\n$black: #212529;\n$banner-dark: #101010;\n$black-light: #6c757d;\n$black-lighter: #888;\n$border-color:#eee;\n$primary-font: \"Plus Jakarta Sans\", sans-serif;\n$secondary-font:\"Plus Jakarta Sans\", sans-serif;\n$green-border : radial-gradient(circle at 100% 100%, #ffffff 0, #ffffff 8px, transparent 8px) 0% 0%/10px 10px no-repeat,\nradial-gradient(circle at 0 100%, #ffffff 0, #ffffff 8px, transparent 8px) 100% 0%/10px 10px no-repeat,\nradial-gradient(circle at 100% 0, #ffffff 0, #ffffff 8px, transparent 8px) 0% 100%/10px 10px no-repeat,\nradial-gradient(circle at 0 0, #ffffff 0, #ffffff 8px, transparent 8px) 100% 100%/10px 10px no-repeat,\nlinear-gradient(#ffffff, #ffffff) 50% 50%/calc(100% - 4px) calc(100% - 20px) no-repeat,\nlinear-gradient(#ffffff, #ffffff) 50% 50%/calc(100% - 20px) calc(100% - 4px) no-repeat,\nlinear-gradient(13deg, rgba(48,171,137,1) 0%, rgba(25,223,209,1) 100%);\n$darkGreenSpan: #187F5F;\n$image-background-banner: #7ED4BD;\n$service-card-gradient: linear-gradient(180deg, rgb(21, 184, 152) 0%, rgb(96, 129, 209) 100%);\n$service-card-button-gradient: linear-gradient(180deg, rgb(97, 225, 190) 0%, rgba(118, 211, 246, 0.2469362745) 100%);\n$service-card-button-dropShadow-color:#013b6b;\n$underline-color: #61e1be;\n$span-background: #2b9778;","/*--------------------\nCommon Styles\n-----------------*/\n\n// @media (min-width: 1200px) {\n//   .container{\n//   }\n// }\n:root {\n  --primary-color: #30ab89;\n}\nhtml {\n  scroll-behavior: smooth;\n}\n\nimg {\n  vertical-align: middle;\n  border-style: none;\n}\n\n.img-thumbnail {\n  padding: 0.25rem;\n  border: 1px solid #dee2e6;\n  background-color: #fff;\n}\n.navbar-nav .dropdown-toggle::after {\n  display: none;\n}\n\n.section {\n  position: relative;\n  padding: 8.125rem 0;\n}\n\n@media (min-width: 768px) {\n  .section {\n    padding: 4.5rem 0;\n  }\n}\n\n.section-top {\n  padding-top: 8.125rem;\n}\n\n.section-bottom {\n  padding-bottom: 8.125rem;\n}\n\n@media (min-width: 768px) {\n  .section-top {\n    padding-top: 10.3125rem;\n  }\n}\n\n.bg-grey {\n  background: #f4f7fc;\n}\n\n/*-------------------\n  BUTTONS STYLE\n----------------=----*/\n\n.btn {\n  font-size: 0.6875rem;\n  font-weight: 700;\n  position: relative;\n  text-transform: uppercase;\n  padding: 1rem 2.4rem;\n  border: 0.1rem solid transparent;\n  transition: all 0.2s ease-in-out;\n  letter-spacing: 0.5px;\n}\n\n.btn-primary-border {\n  border-radius: 8px;\n  border: 3px solid #30ab89;\n  font-size: 0.875rem;\n}\n.btn-circle {\n  display: inline-flex;\n  width: 4.20313rem !important;\n  height: 4.20313rem !important;\n  padding: 0 !important;\n  border-radius: 50%;\n  align-items: center;\n  justify-content: center;\n}\n\n.btn-outline-dark {\n  border: 1px solid#222;\n}\n\n.btn-white {\n  background: #fff;\n  color: #212529;\n}\n\n.btn-trans-white {\n  border: 1px solid#fff;\n  color: #fff;\n  &:hover {\n    color: #fff;\n    opacity: 0.5;\n  }\n}\n\n.btn-outline-dark:hover {\n  background: #222 !important;\n  color: #fff !important;\n}\n\n.btn.btn-link {\n  color: #212529;\n}\n\n.btn:focus {\n  box-shadow: none !important;\n}\n\n.btn-circled {\n  border-radius: 75px;\n}\n\n.bg-primary,\n.btn-primary,\n.btn-white:hover {\n  background: #21c87a !important;\n  border-color: #21c87a !important;\n  color: #fff;\n}\n\n.bg-dark,\n.btn-primary:hover {\n  background: #232323 !important;\n  border-color: #232323 !important;\n  color: #fff;\n}\n\n.shadow-sm-2 {\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n}\n\n/*------------------------\n BACKGROUND\n----------------------------*/\n\n.bg-cover {\n  background-repeat: no-repeat;\n  background-position: 50%;\n  background-size: cover;\n}\n\n.bg-cover,\n.bg-overlay,\n.bg-overlay:before {\n  position: absolute;\n  top: 0;\n  right: 0;\n  bottom: 0;\n  left: 0;\n}\n\n.bg-overlay:before {\n  content: \"\";\n  opacity: 0.55;\n  background-color: #212529;\n}\n\n.box-shadow {\n  box-shadow: 0 25px 100px -5px rgba(0, 0, 0, 0.15);\n}\n\n.mt50 {\n  margin-top: 80px;\n}\n.mt30 {\n  margin-top: 30px;\n}\n\n.mb-30 {\n  margin-bottom: 30px;\n}\n\n.bg-primary {\n  background: $primary-color !important;\n}\n\na {\n  color: $primary-color;\n  transition: 0.3s;\n}\n\na:hover,\na:focus {\n  outline: none;\n  text-decoration: none;\n  color: darken($primary-color, 10);\n}\n\n.disabled-text {\n  color: #ffffffcc !important;\n  cursor: not-allowed;\n}\n\n.logo {\n  width: 100%;\n  height: 100%;\n}\n\n.luminous-blend {\n  mix-blend-mode: luminosity !important;\n}\n\n.bg-home {\n  background-color: #101010;\n  background-position: center;\n  background-size: cover;\n  position: relative;\n  overflow: hidden;\n  padding-top: 3rem;\n  height: 80vh;\n  display: flex;\n  align-items: center;\n  padding-bottom: 3rem;\n  @media (max-width: 991px) {\n    padding-top: 2rem;\n  }\n}\n.bg-home::before {\n  content: \"\";\n  position: absolute;\n  width: 50vw;\n  aspect-ratio: 1 / 1;\n  background: #187f5f1a;\n  border-radius: 100%;\n  left: -50%;\n  transform: translate(50%, -55%);\n  top: 50%;\n  filter: blur(64px);\n}\n.bg-home::after {\n  content: \"\";\n  position: absolute;\n  width: 42vw;\n  aspect-ratio: 1 / 1;\n  background: #187f5f14;\n  border-radius: 100%;\n  right: -50%;\n  transform: translate(-50%, -55%);\n  top: 50%;\n  filter: blur(64px);\n}\n\n.seed-section {\n  padding: 92px 0;\n  @media (max-width: 991px) {\n    padding: 48px 0;\n  }\n}\n.bg-home .seed-container {\n  max-height: 494px;\n  overflow: hidden;\n  @media (max-width: 991px) {\n    max-height: none;\n  }\n}\n.seed-container {\n  padding: 0 80px;\n  width: 100%;\n  // display: flex;\n  @media (max-width: 1400px) {\n    padding: 0 72px;\n    width: 100%;\n  }\n  @media (max-width: 1200px) {\n    padding: 0 50px;\n    width: 100%;\n  }\n  @media (max-width: 767px) {\n    padding: 0 42px;\n    width: 100%;\n  }\n  @media (max-width: 575px) {\n    padding: 0px;\n    width: 100%;\n  }\n}\n.default-text-black {\n  color: $black-text;\n  font-size: 16px;\n  font-style: normal;\n  font-weight: 400;\n  line-height: normal;\n}\n.blogs-slider-prev,\n.blogs-slider-next {\n  width: 100%;\n  height: 100%;\n  border: 0px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  background: transparent;\n}\n.blogs-slider-prev:focus,\n.blogs-slider-next:focus {\n  outline: none;\n}\n.blogs-slider-prev .blog-button-wrapper,\n.blogs-slider-next .blog-button-wrapper {\n  border: 2px solid #30ab89;\n  border-radius: 50px;\n  padding: 8px 16px 10px;\n  transition: 0.3s ease-in-out;\n}\n.blogs-slider-prev .blog-button-wrapper img {\n  rotate: 180deg;\n  transition: 0.3s ease-in-out;\n}\n.blogs-slider-prev:hover .blog-button-wrapper,\n.blogs-slider-next:hover .blog-button-wrapper {\n  background-color: #30ab89;\n}\n.blogs-slider-prev:hover .blog-button-wrapper img,\n.blogs-slider-next:hover .blog-button-wrapper img {\n  filter: brightness(0) invert(1);\n}\n.blogs-slider .blog-item {\n  height: auto;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  flex-direction: column;\n}\n.blogs-slider .slick-track {\n  display: flex !important;\n}\n@media (max-width: 991px) {\n  .blogs-slider-prev,\n  .blogs-slider-next {\n    width: auto;\n  }\n}\n\n.dropdown-large {\n  // position: static !important;\n}\n.dropdown-menu-large {\n  margin-left: 16px;\n  margin-right: 16px;\n  background: #fafafa;\n  padding: 0px !important;\n  width: 600px;\n  left: 50%;\n  transform: translateX(-50%) !important;\n  @media (max-width: 991px) {\n    transform: translateX(0) !important;\n  }\n}\n.dropdown-menu-large > li > ul {\n  padding: 0;\n  margin: 0;\n}\n.dropdown-menu-large > li > ul > li {\n  list-style: none;\n}\n.dropdown-menu-large > li > ul > li > a {\n  display: block;\n  padding: 3px 20px;\n  clear: both;\n  font-weight: normal;\n  line-height: 1.428571429;\n  color: #333333;\n  white-space: normal;\n}\n.dropdown-menu-large > li ul > li > a:hover,\n.dropdown-menu-large > li ul > li > a:focus {\n  text-decoration: none;\n  color: #262626;\n  background-color: #f5f5f5;\n}\n.dropdown-menu-large .disabled > a,\n.dropdown-menu-large .disabled > a:hover,\n.dropdown-menu-large .disabled > a:focus {\n  color: #999999;\n}\n.dropdown-menu-large .disabled > a:hover,\n.dropdown-menu-large .disabled > a:focus {\n  text-decoration: none;\n  background-color: transparent;\n  background-image: none;\n  filter: progid:DXImageTransform.Microsoft.gradient(enabled = false);\n  cursor: not-allowed;\n}\n.dropdown-menu-large .dropdown-header {\n  color: #212529;\n  font-weight: 600;\n  font-size: 18px;\n  text-wrap: wrap;\n  @media (max-width: 991px) {\n    font-size: 14px;\n  }\n}\n@media (max-width: 768px) {\n  .dropdown-menu-large {\n    margin-left: 0;\n    margin-right: 0;\n  }\n  .dropdown-menu-large > li {\n    margin-bottom: 30px;\n  }\n  .dropdown-menu-large > li:last-child {\n    margin-bottom: 0;\n  }\n  .dropdown-menu-large .dropdown-header {\n    padding: 3px 15px !important;\n  }\n}\n\n.dropdown-large .left-main-page ul {\n  padding-left: 1rem !important;\n}\n\n.dropdown-large .col-sm-12 ul {\n  padding-top: 1rem !important;\n  padding-bottom: 1rem !important;\n  padding-left: 1rem !important;\n}\n.dropdown-large .col-sm-9 li {\n  list-style-type: none;\n}\n.dropdown-large .col-sm-9 ul {\n  @media (max-width: 991px) {\n    padding: 1rem;\n  }\n}\n.dropdown-large .col-sm-9 li a {\n  display: block;\n  width: 100%;\n}\n.dropdown-large .col-sm-12 li {\n  list-style-type: none;\n}\n.dropdown-large .col-sm-12 li a {\n  display: block;\n  width: 100%;\n}\n.dropdown-large .right-small-nav ul li a {\n  font-size: 12px;\n  position: relative;\n  padding-left: 1.5rem;\n  @media (max-width: 991px) {\n    padding-left: 0;\n  }\n}\n// .dropdown-large .right-small-nav {\n//   background: url(../images/industries/chatbot/ai-dropdown-bg.png);\n// }\n.dropdown-large\n  .right-small-nav\n  ul\n  li:not(.dropdown-header):not(.divider)\n  a::before {\n  position: absolute;\n  left: 0.5rem;\n  top: 50%;\n  transform: translate(-55%, -55%);\n  width: 4px;\n  height: 4px;\n  border-radius: 100%;\n  background: #20dfa6;\n  content: \"\";\n  @media (max-width: 991px) {\n    display: none;\n  }\n}\n\n.dropdown-large\n  .right-small-nav\n  ul\n  li:not(.dropdown-header):not(.divider)\n  a:hover::before {\n  background: #fff;\n}\n.dropdown-large .col-sm-12 li a {\n  padding: 4px 6px;\n  border: 0;\n  display: block;\n  width: 100%;\n\n  @media (max-width: 991px) {\n    font-size: 14px;\n  }\n}\n\n.ai-chatbot-niche .box .img-box {\n  position: relative;\n  margin-bottom: 12px;\n}\n.ai-chatbot-niche .box .img-box::before {\n  position: absolute;\n  width: 100%;\n  height: 100%;\n  background: linear-gradient(\n    180deg,\n    rgba(0, 0, 0, 0.499124649859944) 0%,\n    rgba(48, 171, 137, 0.5047268907563025) 100%\n  );\n  content: \"\";\n  top: 0;\n  left: 0;\n}\n.dropdown.dropdown-large {\n  position: static;\n}\n\n.navbar-collapse.collapse.show {\n  height: 120vh;\n}\n\n#backgroundCanvas {\n  opacity: 0.1;\n  position: absolute;\n}\n","/*----------------------\n HEADER STYLE\n-----------------------*/\n\n.header-socials {\n  line-height: 22px;\n  margin-bottom: 0px;\n\n  li {\n    padding: 8px;\n\n    a {\n      color: #21c87a;\n    }\n  }\n}\n\n\n/*-----------------\n LOGO BAR\n-------------------*/\n\n.logo-bar {\n  padding: 2px 0px 60px;\n}\n\n.top-info-block {\n  margin-right: 30px;\n\n  h5,\n  p {\n    margin-bottom: 0px;\n  }\n}\n\n\n.icon-block {\n  margin-right: 20px;\n  color: #21c87a;\n  font-size: 40px;\n  line-height: 20px;\n  font-weight: 400;\n}\n\n\n.top-info-block:last-child {\n  margin-right: 0px;\n}\n\n.header-bar {\n  overflow: visible;\n  position: relative;\n  padding-bottom: 30px;\n}\n\n\n.main-navigation {\n  margin-top: -40px;\n}\n\n\n\n\n/*-----------------------\n HOME-3\n---------------------------*/\n\n.header-white {\n  background: #101010;\n  -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n  border-radius: 0px;\n}\n\n.trans-navigation {\n  @include desktop {\n    background: #101010;\n    -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n    box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n    border-radius: 0px;\n  }\n}\n\n.trans-navigation .navbar-brand h4,\n.site-navigation .navbar-brand h4,\n.site-navigation .navbar-brand h3,\n.trans-navigation .navbar-brand h3 {\n  color: $light;\n}\n\n.banner-content.style-2 {\n  padding-top: 200px;\n}\n\n.trans-navigation .navbar-brand {\n  padding-top: 13px;\n}\n\n\n\n.site-navigation.header-white {\n  border-bottom: 1px solid transparent;\n}\n\n.site-navigation .navbar-brand {\n  padding-top: 13px;\n  margin-right: 20px;\n}\n\n\n.banner-content2 {\n  padding: 200px 0px;\n\n  .display-4 {\n    color: $light;\n    font-weight: 600;\n  }\n\n  p.lead {\n    color: $light;\n  }\n}\n\n\n\n\n\n\n/* =========================\nPRELOADER\n=======================*/\n\n#page-loader {\n  background: $light;\n  height: 100%;\n  width: 100%;\n  position: fixed;\n  z-index: 9999999;\n  // display: none;\n}\n\n.loader-icon {\n  // background: none repeat scroll 0 0 $light;\n  background: url('../../images/icon/logo-gear.png');\n  // border-bottom: 3px solid rgba(19, 19, 19, 0.1) !important;\n  // border-left: 3px solid rgba(19, 19, 19, 0.1) !important;\n  // border-radius: 100px;\n  // -moz-border-radius: 100px;\n  // -webkit-border-radius: 100px;\n  // -o-border-radius: 100px;\n  // -ms-border-radius: 100px;\n  // border-right: 3px solid #1453F2 !important;\n  // border-top: 3px solid rgba(19, 19, 19, 0.1) !important;\n  height: 50px;\n  left: 50%;\n  // margin: -20px 0 0 -20px;\n  position: absolute;\n  // text-align: center;\n  top: 50%;\n  width: 50px;\n  // -webkit-transform: translate(-50%, -50%);\n  // -ms-transform: translate(-50%, -50%);\n  // transform: translate(-50%, -50%);\n}\n\n.colored-border {\n  border-color: $light;\n}\n\n.fa-spin {\n  -webkit-animation: fa-spin 1s infinite linear;\n  animation: fa-spin 1s infinite linear;\n}\n\n@-webkit-keyframes fa-spin {\n  0% {\n    -webkit-transform: rotate(0deg);\n    transform: rotate(0deg);\n  }\n\n  100% {\n    -webkit-transform: rotate(359deg);\n    transform: rotate(359deg);\n  }\n}\n\n@keyframes fa-spin {\n  0% {\n    -webkit-transform: rotate(0deg);\n    transform: rotate(0deg);\n  }\n\n  100% {\n    -webkit-transform: rotate(359deg);\n    transform: rotate(359deg);\n  }\n}\n",".service-banner {\n    min-height: 400px;\n    background: url(/images/services-page/ai-services/banner-bg.png);\n    background-repeat: no-repeat;\n    background-position: right;\n    padding: 80px 80px 80px;\n    position: relative;\n    @media(max-width:1200px) {\n        padding: 80px 46px 80px;\n    }\n    @media(max-width:991px) {\n        padding: 60px 46px 60px;\n        height: auto;\n    }\n}\n.service-banner::after {\n    position: absolute;\n    left: 0;\n    top: 0;\n    width: 100%;\n    height: 100%;\n    content: \"\";\n    z-index: -1;\n    background: linear-gradient(180deg, #101010 0%, #061511 100%);\n}\n.service-banner .path {\n  gap: 10px;\n  position: absolute;\n}\n.service-banner-content {\n  padding: 72px 0;\n}\n.service-banner-content .left-container p {\n    line-height: normal;\n}\n.service-banner-content h1 {\n    font-size: 48px;\n    font-style: normal;\n    font-weight: 700;\n    line-height: normal;\n    color: #FAFAFA;\n    margin-bottom: 20px !important;\n    @media(max-width:1200px) {\n        font-size: 42px;\n    }\n    @media(max-width:767px) {\n        font-size: 32px;\n\n    }\n}\n.service-banner-content h1 span {\n    color: #30AB89;\n}\n.service-banner-content .right-container {\n    max-width: 450px;\n    @media(max-width:1200px) {\n        max-width: 45%;\n    }\n}\n\n.tag-line{\n    font-size: 24px;\n    margin-bottom: 40px;\n\n   \n}","/*--------------------------\nPAGE BANNER\n--------------------------*/\n\n.page-banner-area {\n  padding: 180px 0px;\n}\n.page-contact {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/p-6.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n.page-service {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/service.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-about {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/about.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-pricing {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/img2.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-project {\n  position: relative;\n  padding: 180px 0px;\n  background: url(\"../images/banner/p-4.jpg\") fixed 50% 50% no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.page-banner-content h1 {\n  color: $light;\n  text-align: center;\n  font-size: 32px;\n  max-width: 500px;\n  margin: auto;\n\n  @media (max-width: 767px) {\n    font-size: 28px;\n  }\n  @media (max-width: 565px) {\n    font-size: 24px;\n  }\n}\n\n.page-banner-content p {\n  color: #21c87a;\n  font-weight: 600;\n}\n\n.meeting-button-wrapper {\n  display: flex;\n  gap: 1rem;\n  justify-content: center;\n  @media (max-width: 565px) {\n    flex-direction: column;\n  }\n  button,\n  a {\n    border: 0px;\n    font-weight: bold;\n    border-radius: 12px;\n    padding: 8px 12px;\n    background-color: white;\n    color: black;\n  }\n  .filled-button {\n    background-color: #21c87a;\n    color: white;\n  }\n}\n.page-banner-content p {\n  //   color: $border-color;\n}\n\n.form-control {\n  border-radius: 0px;\n  height: 45px;\n}\n","/*-------------------\n   MENU\n----------------------*/\n.navbar-toggler-icon {\n  display: inline-block;\n  width: 1.5em;\n  height: 1.5em;\n  content: \"\";\n  vertical-align: middle;\n  background: no-repeat 50%;\n  background-size: 100% 100%\n}\n\n.navbar-dark .navbar-toggler {\n  color: #fff;\n  border-color: rgba(255,255,255,.1);\n  padding: 10px 12px;\n  &:focus {\n    outline: 0;\n  }\n}\n\n.main-nav {\n  margin-bottom: -45px;\n  z-index: 999;\n}\n\n.navbar-nav .nav-link {\n  padding-right: 1rem !important;\n  padding-left: 1rem !important;\n  transition: .3s;\n}\n\n.navbar-dark .navbar-nav .nav-link {\n  color: $light;\n  font-weight: 500;\n  letter-spacing: .5px;\n  // text-transform: uppercase;\n}\n\n.rounded-radius {\n  border-radius: 5px;\n}\n\n.navbar {\n  position: relative;\n  padding: 0rem 0rem 1rem;\n  display: flex;\n  flex-direction: column;\n\n\n  &:before {\n    position: absolute;\n    z-index: -1;\n    top: 0;\n    right: 0;\n    bottom: 0;\n    left: 0;\n    content: \"\";\n    transition: opacity .15s linear;\n    opacity: 0;\n    border-bottom: 1px solid rgba(0, 0, 0, .1);\n    background-color: $light;\n\n  }\n}\n\n.dropdown-toggle::after {\n  margin-left: .255em;\n  vertical-align: 1px;\n  content: \"\\f078\";\n  border: 0;\n  font-family: \"Font Awesome 5 Free\";\n  font-size: 12px;\n}\n\n.fixed-top {\n  position: fixed;\n  z-index: 1030;\n  right: 0;\n  left: 0;\n}\n\n\n.navbar-dark {\n  color: $light;\n}\n\n\n.navbar-light {\n  color: $black;\n\n  &:before {\n    opacity: 1;\n  }\n}\n\n\n.navbar .nav-item-divider {\n  display: none;\n\n  .nav-link {\n    opacity: .25;\n  }\n}\n\n.header-bar.fixed-header .main-navigation {\n  position: fixed;\n  left: 0;\n  top: 0;\n  width: 100%;\n  background: #101010;\n  border-color: transparent;\n\n}\n\n.primary-btn {\n  padding: 0.5rem 1.25rem; border-radius: 2rem; background-color: #30ab89;\n  font-weight: 500;\n  color: #fff;\nfont-size: 1rem;\n  .nav-link {\n    padding: 0;\n    font-weight: 500;\n  }\n}\n\n\n.primary-btn:hover, .primary-btn:visited{\n  color: #fff;\n}\n/*-------------------\n  DROPDOWN MENU\n----------------------*/\n.has-dropdown {\n  .dropdown-menu {\n    border: none;\n    box-shadow: 0 0 25px 0 rgba(0, 0, 0, 0.08);\n    padding: 0;\n    margin: 0;\n\n    @include desktop {\n      text-align: center;\n      float: left !important;\n      width: 100%;\n      margin: 0;\n    }\n\n    a {\n      font-weight: normal;\n      color: #808080;\n      padding: 10px 20px;\n      @include transition (all, 0.3s, ease);\n      border-bottom: 1px solid #eee;\n      border-radius: 4px;\n\n      &:focus,\n      &:hover {\n        background: $primary-color;\n\n        color: $light;\n      }\n    }\n  }\n}\n\n.dropleft .dropdown-menu,\n.dropright .dropdown-menu {\n  margin: 0;\n}\n\n.dropleft .dropdown-toggle::before,\n.dropright .dropdown-toggle::after {\n  font-weight: bold;\n  font-family: \"Font Awesome 5 Free\";\n  border: 0;\n  font-size: 10px;\n  vertical-align: 1px;\n}\n\n.dropleft .dropdown-toggle::before {\n  content: \"\\f053\";\n  margin-right: 7px;\n}\n\n.dropright .dropdown-toggle::after {\n  content: \"\\f054\";\n  margin-left: 7px;\n}\n\n.dropdown-item {\n  padding: .6rem 1.4rem;\n  text-transform: uppercase;\n  font-size: 12px;\n  font-weight: 700;\n}\n\n.dropdown-submenu:hover>.dropdown-item,\n.dropdown-item:hover {\n  background: #101010;\n  color: $light !important;\n}\n\n.dropdown-item.active {\n  text-decoration: underline;\n  background-color: transparent;\n  color: inherit;\n}\n.dropdown-submenu.active>.dropdown-toggle {\n  text-decoration: underline;\n  color: inherit;\n}\n\nul.dropdown-menu li {\n  padding-left: 0px !important;\n}\n\n@media (min-width:992px) {\n  .dropdown-menu {\n    transition: all .2s ease-in, visibility 0s linear .2s, transform .2s linear;\n    display: block;\n    visibility: hidden;\n    opacity: 0;\n    min-width: 200px;\n    transform: translateY(15px);\n  }\n\n  .dropdown:hover>.dropdown-menu {\n    visibility: visible;\n    transition: all .35s ease 0s;\n    opacity: 1;\n    transform: translateY(0);\n  }\n}\n\n.pt-60px{\n  padding-top: 60px !important;\n}\n@media (max-width:992px) {\n  .position-md-sticky {\n    position: sticky !important;\n  }\n}","// Transition\n@mixin transition($what: all, $time: 0.2s, $how: ease-in-out) {\n    -webkit-transition: $what $time $how;\n    -moz-transition:    $what $time $how;\n    -ms-transition:     $what $time $how;\n    -o-transition:      $what $time $how;\n    transition:         $what $time $how;\n}\n\n// Transform\n@mixin transform($transforms) {\n\t   -moz-transform: $transforms;\n\t     -o-transform: $transforms;\n\t    -ms-transform: $transforms;\n\t-webkit-transform: $transforms;\n          transform: $transforms;\n}\n// rotate\n@mixin rotate ($deg) {\n  @include transform(rotate(#{$deg}deg));\n}\n \n// scale\n@mixin scale($scale) {\n\t @include transform(scale($scale));\n} \n// translate\n@mixin translate ($x, $y) {\n   @include transform(translate($x, $y));\n}\n// skew\n@mixin skew ($x, $y) {\n   @include transform(skew(#{$x}deg, #{$y}deg));\n}\n//transform origin\n@mixin transform-origin ($origin) {\n    moz-transform-origin: $origin;\n\t     -o-transform-origin: $origin;\n\t    -ms-transform-origin: $origin;\n\t-webkit-transform-origin: $origin;\n          transform-origin: $origin;\n}","/*----------------------\n BANNER STYLE\n-----------------------*/\n\n.py-7 {\n  padding: 7.5rem 0;\n}\n\n.py-4 {\n  padding: 4.5rem 0;\n}\n\n.py-8 {\n  padding: 8.5rem 0;\n}\n\n.main-banner {\n  h5 {\n    margin-bottom: 20px;\n  }\n  h1.display-4 {\n    line-height: 65px;\n  }\n}\n\n.main-banner p.lead,\n.banner-content p.lead {\n  margin-bottom: 2.5rem !important;\n}\n\n/*-------------------------\n HOME -2\n-----------------------------*/\n#banner {\n  position: relative;\n  background: url(\"/images/bg/banner_bg.jpg\") no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n  // background: #101010;\n}\n\n.banner-content {\n  padding: 150px 0px;\n  padding-right: 30px;\n  p {\n    color: $border-color;\n    padding-right: 80px;\n    margin-bottom: 30px !important;\n  }\n  .display-4 {\n    color: $light;\n    font-weight: 600;\n  }\n}\n\n#banner .overlay {\n  opacity: 0.7;\n}\n\n.banner-contact-form {\n  padding: 45px 40px;\n  margin-top: 30px;\n\n  .form-control {\n    border-radius: 0px;\n    height: 45px;\n  }\n\n  textarea.form-control {\n    height: auto;\n  }\n}\n\n.transform-y-10 {\n  transform: translateY(2%);\n}\n\n.slick-dots {\n  position: absolute;\n  display: flex;\n  justify-content: center;\n  bottom: 0%;\n  left: -32px;\n  @media (max-width: 1400px) {\n    // left: -40px;\n  }\n  @media (max-width: 1200px) {\n    left: -35px;\n  }\n  @include desktop {\n    bottom: 4%;\n    left: auto;\n  }\n  @include tablet-xs {\n    bottom: 95%;\n  }\n  // @include mobile {\n  //   bottom: 95%;\n  // }\n  @include tablet {\n    bottom: 4%;\n    padding-left: 0;\n  }\n}\n.slick-dots li {\n  // display: block;\n  width: auto;\n  height: auto;\n  margin-top: 10px;\n  @media (min-width: 992px) {\n    display: block;\n  }\n}\n.bg-home .slick-carousel {\n  height: 55vh;\n  margin-top: 2rem;\n  @media (max-width: 400px) {\n    height: 60vh;\n  }\n}\n.bg-home .slick-dots {\n  gap: 12px;\n}\n.bg-home .slick-dots li a {\n  gap: 8px;\n}\n\n.slick-dots li svg:nth-child(1) {\n  display: block;\n}\n\n.slick-dots li svg:nth-child(2) {\n  display: none;\n}\n\n.slick-dots li.slick-active svg:nth-child(1) {\n  display: none;\n}\n.slick-dots li span {\n  font-weight: 700;\n  color: #707070;\n  @media (max-width:400px) {\n    font-size: 12px;\n  }\n}\n.slick-dots li.slick-active span {\n  color: white;\n  font-size: 14px;\n}\n\n.slick-dots li.slick-active svg:nth-child(2) {\n  display: block;\n}\n.slick-carousel {\n  height: auto;\n}\n\n//.slider-container{\n//  display: flex;\n//  justify-content: space-between;\n//  align-items: center;\n//  position: relative;\n//  width: 100%;\n//  text-align: left;\n//  @include large-desktop{\n//    height: 50vh;\n//  }\n//  @include desktop{\n//    height: 60vh;\n//  }\n//  @include tablet{\n//    text-align: center;\n//    margin-top: 60px;\n//  }\n//  @include mobile{\n//    flex-direction: column;\n//    justify-content: center;\n//    margin-top: 80px;\n//    height: auto;\n//  }\n//  @include tablet-xs{\n//    flex-direction: column;\n//    justify-content: center;\n//    margin-top: 50px;\n//    height: auto;\n//  }\n//\n//\n//}\n//\n//.slider-typo{\n//  @media (min-width: 1201px) and (max-width:2000px) {\n//    width: 55%;\n//    //position: absolute;\n//    margin-top:12%;\n//  }\n//  @include large-desktop{\n//    position: absolute;\n//    left: 2%;\n//    top: 30%;\n//    width: 70%;\n//  }\n//  @include desktop{\n//    width: 100%;\n//    position: absolute;\n//    top: 10vh;\n//    left: -3vw;\n//  }\n//  @include tablet{\n//    position: absolute;\n//    top: -4%;\n//    left: 2%;\n//    width: 100%;\n//    transform: translateX(0);\n//    font-size: 50px;\n//  }\n//  @include tablet-xs{\n//    position: static;\n//    width: 100%;\n//  }\n//  @include mobile{\n//    position: static;\n//    width: 100%;\n//  }\n//\n//\n//}\n//\n//\n//.slider-img{\n//\n//  @media (min-width: 1201px) and (max-width:2000px) {\n//   position: absolute;\n//    right: -5%;\n//    bottom:-27vh;\n//  }\n//  @media (min-width: 1300px) and (max-width:1600px) {\n//    position: absolute;\n//    right: -5%;\n//    bottom:-30vh;\n//  }\n//  @include large-desktop{\n//    position: absolute;\n//    top: 10%;\n//    right: -5%;\n//  }\n//  @include desktop{\n//    position: absolute;\n//    right: -20vw;\n//    top:15vh;\n//  }\n//  @include tablet{\n//    //position: absolute;\n//    //right: -2vw;\n//    //top: 20vh;\n//    position: static;\n//    transform: translate(-8%,30%);\n//  }\n//  @include tablet-xs{\n//    //position: absolute;\n//    //right: -1vw;\n//    //top: 20vh;\n//    position: static;\n//    transform: translateX(-5%);\n//  }\n//\n//  @include mobile{\n//    position: static;\n//    transform: translateX(-5%);\n//  }\n//\n//}\n//\n\n//.container{\n//  position: relative;\n//  height: 60vh;\n//}\n\n.slick-carousel {\n  width: 100%;\n}\n.text-primary {\n  color: #30ab89 !important;\n}\n// .slider-container h1 {\n// @include desktop {\n//   font-size: 20px;\n// }\n// }\n\n.slider-container {\n  z-index: 10000;\n  position: relative;\n  width: 100%;\n  display: flex;\n  flex-direction: row;\n  align-items: center;\n  justify-content: space-between;\n  // padding: 20px;\n  box-sizing: border-box;\n  height: fit-content;\n  @include desktop {\n    padding: 0 20px;\n    flex-direction: column;\n    justify-content: center;\n    align-items: center;\n    height: 69vh;\n  }\n\n  .text-primary {\n    background: none;\n  }\n\n  // @include mobile {\n  //   height: 70vh;\n  // }\n}\n.slider-typo {\n  flex: 1;\n  width: 100%;\n  display: flex;\n  max-width: 800px;\n  // align-items: center;\n  // height: 69vh;\n  @include desktop {\n    text-align: center;\n    justify-content: center;\n  }\n}\n.img-cont {\n  display: flex;\n  justify-content: flex-end;\n  align-items: flex-end;\n  margin-top: auto;\n\n  @include tablet {\n    justify-content: center;\n  }\n}\n#plantImg {\n  filter: grayscale(100%);\n}\n.slider-img {\n  width: 100%;\n  height: auto;\n  transform: translateY(5%);\n  filter: grayscale(100%);\n\n  img {\n    width: 100%;\n  }\n}\n\nsection.slick-dotted.slick-slider {\n  margin-bottom: 0;\n}\n\n@media (min-width: 992px) {\n  .carousel-cont {\n    padding-left: 10px;\n  }\n\n  .slider-img {\n    margin-right: 2rem;\n  }\n}\n@media (min-width: 768px) and (max-width: 992px) {\n  // .slider-typo {\n  //   margin-top: 120px;\n  // }\n  .slider-container {\n    height: 75vh;\n  }\n  .slider-img {\n    margin-right: 1rem;\n  }\n}\n\n@media (max-width: 1000px) {\n  // .slider-typo {\n  //   margin-top: 100px;\n  // }\n}\n\n.stack {\n  display: grid;\n  grid-template-columns: 1fr;\n}\n\n.stack span {\n  font-weight: bold;\n  grid-row-start: 1;\n  grid-column-start: 1;\n  // font-size: 4rem;\n  --stack-height: calc(100% / var(--stacks) - 1px);\n  --inverse-index: calc(calc(var(--stacks) - 1) - var(--index));\n  --clip-top: calc(var(--stack-height) * var(--index));\n  --clip-bottom: calc(var(--stack-height) * var(--inverse-index));\n  clip-path: inset(var(--clip-top) 0 var(--clip-bottom) 0);\n  animation: stack 340ms cubic-bezier(0.46, 0.29, 0, 1.24) 1 backwards\n      calc(var(--index) * 120ms),\n    glitch 2s ease infinite 2s alternate-reverse;\n  }\n\n.stack span:nth-child(odd) {\n  --glitch-translate: 8px;\n}\n.stack span:nth-child(even) {\n  --glitch-translate: -8px;\n}\n\n@keyframes stack {\n  0% {\n    opacity: 0;\n    transform: translateX(-50%);\n    text-shadow: -2px 3px 0 red, 2px -3px 0 blue;\n  }\n  60% {\n    opacity: 0.5;\n    transform: translateX(50%);\n  }\n  80% {\n    transform: none;\n    opacity: 1;\n    text-shadow: 2px -3px 0 red, -2px 3px 0 blue;\n  }\n  100% {\n    text-shadow: none;\n  }\n}\n\n@keyframes glitch {\n  0% {\n    text-shadow: -2px 3px 0 red, 2px -3px 0 blue;\n    transform: translate(var(--glitch-translate));\n  }\n  2% {\n    text-shadow: 2px -3px 0 red, -2px 3px 0 blue;\n  }\n  4%,\n  100% {\n    text-shadow: none;\n    transform: none;\n  }\n}\n\n.snowflake {\n  position: absolute;\n  bottom: 0;\n  background: white;\n  border-radius: 50%;\n  opacity: 0;\n  transform: translateY(0);\n  animation: snowfall 5s ease-in-out infinite;\n}\n\n@keyframes snowfall {\n  0% {\n    opacity: 0;\n    transform: translateY(0);\n  }\n  20% {\n    opacity: 1;\n  }\n  80% {\n    opacity: 1;\n  }\n  100% {\n    opacity: 0;\n    transform: translateY(-100vh);\n  }\n}\n","\n#banner-3{\n    position: relative;\n    background: url(\"../images/banner/banner.jpg\")no-repeat;\n    -webkit-background-size: cover;\n    background-size: cover;\n}\n\n#banner-4{\n    position: relative;\n    background: url(\"../images/banner/banner-2.jpg\")no-repeat;\n    -webkit-background-size: cover;\n    background-size: cover;\n}\n\n",".seed-stats {\n  background: url(../../images/stats/stats-bg.png);\n  background-size: cover;\n  background-position: center;\n  background-repeat: no-repeat;\n}\n.default-section-heading {\n  color: $black-text;\n  font-size: 32px;\n  font-weight: 600;\n}\n.default-section-heading span {\n  color: $primary-colors;\n}\n.default-text-para {\n  color: $black-text;\n  font-style: normal;\n  line-height: normal;\n}\n.seed-stats .stats-count .count {\n  color: $black-text;\n  font-size: 44px;\n  font-weight: 800;\n  @media (max-width:767px) {\n    font-size: 32px;\n  }\n}\n.seed-stats .stats-count p {\n  color: $black-text;\n  font-size: 12px;\n  font-weight: 500;\n}\n","\n/*----------------------\n FEATURE STYLE\n-----------------------*/\n.img-icon-block {\n    position: relative;\n\n    &:before {\n        position: absolute;\n        content: \"\";\n        top: -2rem;\n        background: #A5EBD7;\n        opacity: 1;\n        width: 84px;\n        left: 5rem;\n        height: 84px;\n        border-radius: 50%;\n        z-index: 1;\n    }\n\n    img{\n        font-size: 58px;\n        z-index: 3!important;\n        color: #333;\n        position: relative;\n        width: 48px;\n        height: 48px;\n    }\n}\n\n/*--------------------------\nABOUT-2\n---------------------------*/\n#about .img-block{\n    position: relative;\n      -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n    box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n\n    img{\n        border: 5px solid $primary-color;\n    }\n}\n.pt-6{\n    padding-top: 4.5rem;\n}\n.img-icon i{\n    font-size: 60px;\n}\n#feature .head-title-text {\n    color: var(--text-color, #2C2C2C);\n    text-align: center;\n    font-family: Plus Jakarta Sans;\n    font-size: 20px;\n    font-style: normal;\n    font-weight: 500;\n    line-height: normal;\n    max-width: 600px;\n    display: inline-block;\n}\n#feature .head-title-text span {\n    color: #30AB89;\n    font-weight: 700;\n}\n@media screen and (max-width: 991px) {\n.img-icon-block {\n        &:before {\n            width: 70px;\n            height: 70px;\n        }\n        img {\n            width: 50px;\n            height: 50px;\n        }\n    }\n    #feature .head-title-text {\n        font-size: 20px;\n    }\n}","/*----------------------\n SERVICE\n-----------------------*/\n\n.service-container {\n  margin: auto;\n  max-width: 1540px;\n  \n  margin: 80px auto;\n\n  @media (max-width: 1154px) {\n    margin: 50px auto;\n  }\n}\n\nh5.subtitle {\n  color: $primary-color;\n  margin-bottom: 10px;\n  font-weight: 300;\n}\n\n#service-subheading {\n  color: $black-text;\n  text-align: center;\n  font-size: 16px;\n  font-style: normal;\n  font-weight: 400;\n  line-height: 1.5;\n\n  @media (max-width: 1154px) {\n    font-size: 14px;\n  }\n}\n\n#service-heading {\n  margin-bottom: 14px !important;\n  font-size: 32px;\n  line-height: 1.25;\n  @media (max-width: 1154px) {\n    font-size: 25px;\n  }\n  span {\n    color: #30AB89;\n  }\n}\n\n.service-heading {\n  margin-bottom: 50px !important;\n}\n\n.service-images {\n  margin-bottom: -200px;\n  border: 10px solid $light;\n}\n\n.service-content {\n  padding-top: 60px;\n  padding-left: 15px;\n\n  h1 {\n    margin-bottom: 20px;\n    margin-top: 15px;\n  }\n}\n\n.service-icon {\n  margin-right: 20px;\n  color: $light;\n  font-size: 25px;\n  width: 50px;\n  height: 50px;\n  background: #A5EBD7;\n  text-align: center;\n  border-radius: 50%;\n  padding-top: 5px;\n}\n\n.service-block {\n  margin-bottom: 50px;\n}\n\n.service-inner-content h4 {\n  // text-transform: uppercase;\n}\n\n/*----------------------\n WEB SERVICES\n-----------------------*/\n#services-2{\n  position: relative;\n  padding: 20px;\n  -webkit-background-size: cover;\n  background-size: cover;\n  background-color: #FAFAFA;\n  color: $black-text;\n}\n\n.service-blocks {\n  display: grid;\n  grid-template-columns: 1fr 1fr 1fr;\n  gap: 1rem;\n  @media (max-width: 1154px) {\n    grid-template-columns: 1fr 1fr;\n  }\n\n  @media (max-width: 800px) {\n    grid-template-columns: 1fr;\n  }\n  // @media (max-width: 400px) {\n  //   gap: 12px !important;\n  // }\n}\n\n.key-features-blocks {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 1rem;\n  @media (max-width: 1154px) {\n    grid-template-columns: 1fr;\n  }\n\n  \n  // @media (max-width: 400px) {\n  //   gap: 12px !important;\n  // }\n}\n\n.service-blocks-4 {\n  display: grid;\n  grid-template-columns: 1fr 1fr 1fr 1fr;\n  gap: 1rem;\n  @media (max-width: 1154px) {\n    grid-template-columns: 1fr 1fr 1fr;\n  }\n\n  @media (max-width: 800px) {\n    grid-template-columns: 1fr;\n  }\n  // @media (max-width: 400px) {\n  //   gap: 12px !important;\n  // }\n}\n\n// .web-service-block:hover {\n//   border: 1px solid #2b9778;\n// }\n.web-service-block {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n  padding: 1.5rem;\n  transition: 0.3s;\n  border-radius: 5px;\n  // border: 1px solid #fff;\n  cursor: pointer;\n\n  .image-container {\n    height: 4rem;\n  }\n  .image-container-black {\n    height: 4rem;\n  }\n  .image-container-black img{\n    height: 100%;\n  }\n  .image-container img {\n    height: 100%;\n  filter: brightness(1) invert(1);\n  }\n\n  h3 {\n    font-size: 25px;\n    margin: 0;\n    transition: 0.3s;\n    color: $black-text;\n  }\n\n\n  p {\n    font-size: 15px;\n    font-weight: 400;\n    transition: 0.3s;\n    color: $black-text;\n    line-height: 1.5;\n    \n  }\n\n  a {\n    color: #30AB89 !important;\n    font-size: 18px;\n    font-weight: 700;\n    cursor: pointer;\n    margin-top: auto;\n  }\n}\n\n.service-img {\n  margin-bottom: -200px !important;\n  border: 10px solid $light;\n  margin: auto;\n}\n\n.why-choose-card{\n  border: solid 1px #dcdcdc\n}\n.card-hover-effect{\n  transition: all 200ms;\n}\n.card-hover-effect:hover{\n  transform: scale(1.02);\n  box-shadow: 0px 0px 15px 0px #20c9963c;\n\n\n}\n\n\n.how-it-works-card{\n  display: flex;\n  flex-direction: column;\n  gap: 1px;\n  p{\n\n    font-size: 16px;\n  }\n}","/*----------------------\n PRoject\n-----------------------*/\n#projects-wrap {\n  position: relative;\n  background: url(\"../images/bg/banner_bg.jpg\") no-repeat;\n  -webkit-background-size: cover;\n  background-size: cover;\n\n  p.lead {\n    color: #a9a9a9 !important;\n  }\n}\n\n.overlay {\n  position: absolute;\n  left: 0;\n  top: 0;\n  width: 100%;\n  height: 100%;\n  background: rgba(0, 0, 0, 0.92);\n}\n\n.overlay.feature-overlay {\n  background-image: linear-gradient(\n    30deg,\n    rgba(121, 110, 255, 0.95) 0%,\n    #30ab89 100%\n  );\n  opacity: 0.9;\n}\n\n#projects {\n  margin-top: -60px;\n}\n\n.single-project img {\n  border-radius: 10px;\n}\n\n.project-content {\n  text-align: center;\n  padding: 40px 20px;\n  position: relative;\n  .btn {\n    padding: 0.7rem 1.7rem;\n    border-radius: 25px;\n  }\n  p {\n    margin-top: 20px;\n  }\n  h4 {\n    text-transform: capitalize;\n  }\n}\n\n.project-content-block {\n  padding: 70px 40px;\n  margin-left: -120px;\n  background: #f4f7fc;\n  position: absolute;\n  bottom: -70px;\n  border: 15px solid $light;\n  -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n  box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n  h4 {\n    color: $primary-color;\n  }\n  p {\n    margin-top: 25px;\n  }\n}\n\n/*-------------------------\n PORTFOLIO-2\n---------------------------*/\n\n.single-work {\n  -webkit-transition: all 300ms ease-in-out;\n  -o-transition: all 300ms ease-in-out;\n  transition: all 300ms ease-in-out;\n}\n\n.overlay-content-block {\n  position: absolute;\n  content: \"\";\n  bottom: 20px;\n  width: 100%;\n  left: 30px;\n  padding: 30px 20px;\n  background: $light;\n  opacity: 0;\n  visibility: hidden;\n  -webkit-transition: all 300ms ease-in-out;\n  -o-transition: all 300ms ease-in-out;\n  transition: all 300ms ease-in-out;\n  border-radius: 5px 0px 0px 5px;\n\n  .icon {\n    width: 50px;\n    height: 50px;\n    display: inline-block;\n    text-align: center;\n    padding-top: 12px;\n    border-radius: 100%;\n    position: absolute;\n    left: 30px;\n    top: -23px;\n    background: $primary-color;\n    color: $light;\n  }\n\n  h4 {\n    margin-bottom: 0px;\n    margin-top: 10px;\n  }\n}\n\n.work-block {\n  position: relative;\n  border: 5px solid $light;\n\n  img {\n    width: 100%;\n    border-radius: 10px;\n    box-shadow: 0px 2px 10px 0px rgba(0, 0, 0, 0.14);\n    object-fit: cover;\n    aspect-ratio: 4/3;\n  }\n\n  &:hover .overlay-content-block {\n    opacity: 1;\n    visibility: visible;\n  }\n\n}\n\n.card-content {\n  padding: 0.7rem 0.5rem 0;\n\n  h4 {\n    color: var(--text-color, #2C2C2C);\n    font-size: 24px;\n    font-style: normal;\n    font-weight: 600;\n    line-height: normal;\n  }\n  p {\n    color: var(--text-color, #2C2C2C);\nfont-size: 14px;\nfont-style: normal;\nfont-weight: 400;\nline-height: normal;\n  }\n  .link {\n    font-weight: 600;\n    color: #30AB89\n  }\n}\n\n/* ==============================\n  SINGEL PROJECTS\n=============================*/\n\n.project-details-info {\n  margin: 40px 0px;\n}\n\n.info-block-2 {\n  float: left;\n  margin-right: 65px;\n  margin-bottom: 40px;\n}\n\n.project-info ul {\n  margin-top: 40px;\n  li {\n    margin-bottom: 30px;\n    padding-right: 20px;\n  }\n}\n\n.project-lg-images img {\n  width: 100%;\n}\n\n.alumni-description {\n  color: var(--text-color, #2c2c2c);\n  text-align: center;\n  font-size: 20px;\n  font-style: normal;\n  font-weight: 500;\n  line-height: normal;\n  color: #343a40;\n  span {\n    color: #30ab89;\n    font-weight: 700;\n  }\n}\n","/*----------------------\n PROCESS\n-----------------------*/\nsection#process {\n  background-image: url(\"../../images/bg/Logo seed.png\");\n  background-repeat: no-repeat;\n  background-size: contain;\n  background-position: left;\n  min-height: 574px;\n  // background-position: 84%;\n}\n#alumni-container {\n  img {\n    filter: none;\n    margin: 30px auto;\n    display: flex;\n    justify-content: center;\n    align-items: center;\n  }\n  p {\n    font-size: 18px;\n    margin: auto;\n    font-family: \"Plus Jakarta Sans\", sans-serif !important;\n  }\n  @media screen and (max-width: 991px) {\n    p {\n      font-size: 24px !important;\n    }\n  }\n  @media screen and (max-width: 767px) {\n    p {\n      font-size: 18px !important;\n    }\n  }\n  @media screen and (max-width: 575px) {\n    p {\n      font-size: 16px !important;\n    }\n  }\n}\n#bytecorpimg {\n  width: 45px;\n}\n#Foliologo {\n  width: 150px;\n}\n#nustlogo {\n  width: 170px;\n}\n#JafferLogo {\n  width: 120px;\n}\n\n.process-block {\n  margin: auto;\n  text-align: center;\n  img {\n    border-radius: 5px;\n    margin-bottom: 45px;\n    // filter: grayscale(100%);\n  }\n  h3 {\n    margin-bottom: 15px;\n  }\n}\n\n.bottom-bar {\n  margin-top: 40px;\n  max-width: 860px;\n  display: flex;\n  flex-direction: row;\n  justify-content: space-between;\n  align-items: center;\n  margin: auto;\n  font-family: $secondary-font;\n\n  h2 {\n    text-align: center;\n    color: var(--heading-color, #202020);\n    font-size: 48px;\n    font-style: normal;\n    font-weight: 800;\n    line-height: normal;\n  }\n\n  p {\n    color: var(--text-color, #2c2c2c);\n    text-align: center;\n    font-size: 14px;\n    font-style: normal;\n    font-weight: 500;\n    line-height: normal;\n  }\n  div {\n    margin-top: 24px;\n  }\n}\n#section-para {\n  font-size: 24px;\n  font-weight: 400;\n  span {\n    color: $span-background;\n    font-weight: 700;\n  }\n}\n\n.earn-trust {\n  max-width: 479px;\n  color: var(--text-color, #2c2c2c);\n  text-align: center;\n  font-size: 20px;\n  font-style: normal;\n  font-weight: 500;\n  line-height: normal;\n}\n\n.earn-trust span {\n  color: var(--main-color-1, #30ab89);\n  font-size: 20px;\n  font-style: normal;\n  font-weight: 700;\n  line-height: normal;\n}\n\n.section-heading {\n  display: flex;\n  justify-content: center;\n}\n","\n\n/*----------------------\n PRICING\n-----------------------*/\n\n.price-block {\n    margin: 20px 0px 30px;\n    h2 {\n        font-size: 80px;\n        font-weight: 700;\n        position: relative;\n        display: inline-block;\n\n        small {\n            position: absolute;\n            top: 20px;\n            font-size: 16px;\n            left: -9px;\n        }\n    }\n\n     h6 {\n        font-size: 14px;\n        border-top: 1px solid $border-color;\n        border-bottom: 1px solid $border-color;\n        padding: 7px;\n        text-transform: capitalize;\n        width: 50%;\n        margin: 10px auto;\n\n    }\n}\n\n\n\n.price-features {\n    margin: 30px 0px 50px;\n    li {\n        font-size: 16px;\n        padding: 5px 0px;\n        position: relative;\n        padding-left: 30px;\n\n        &:before{\n            position: absolute;\n            content:\"\\f00c\";\n            font-family: \"Font Awesome 5 Free\";\n            left: 0px;\n            top: 5px;\n            color: $primary-color;\n            font-weight: 900;\n        }\n    }\n}\n\n\n\n.pricing-block .price-features li{\n    padding-left: 0px;\n    &:before{\n        display: none;\n    }\n}\n\n\n\n/*--------------------------\nPRICING-2\n---------------------------*/\n.pricing-box{\n    border: 1px solid $border-color;\n    padding: 60px;\n    -webkit-transition: all 300ms ease-in-out;\n    -o-transition:all 300ms ease-in-out ;\n    transition:all 300ms ease-in-out ;\n\n    .price-block h2 span{\n        font-size: 12px;\n        font-weight: normal;\n        text-transform: capitalize;\n    }\n    &:hover{\n        background: rgb(29, 28, 28);\n        border-color: rgb(29, 28, 28);\n    }\n\n    &:hover .price-features li{\n        color: $border-color;\n    }\n    &:hover .price-block h2{\n        color: $light;\n    }\n    &:hover h3{\n        color: $light;\n    }\n    &:hover .btn{\n        background: $light!important;\n        color: #000!important;\n    }\n\n}\n\n","/*----------------------\n BLOG SECTION\n-----------------------*/\n.blog-box {\n  position: relative;\n  display: flex;\n  flex-direction: column;\n    align-items: center;\n    height: 100%;\n\n  .blog-img-box img {\n    width: 100%;\n    border-radius: 10px;\n    box-shadow: 0px 2px 10px 0px rgba(0, 0, 0, 0.14);\n    object-fit: contain;\n    aspect-ratio: 16/11;\n    background-color: #101010;\n  }\n}\n\n.single-blog {\n  padding-top: 25px;\n  position: relative;\n  height: 100%;\n}\n\n.bg-light .single-blog {\n  padding: 40px;\n  text-align: center;\n  border-bottom: 1px solid $border-color;\n}\n\n.blog-content {\n    display: flex;\n    flex-direction: column;\n    height: 100%;\n    flex-grow: 1;\n  a h3 {\n    color: var(--text-color, #2c2c2c);\n    font-size: 20px;\n    font-style: normal;\n    font-weight: 600;\n    line-height: normal;\n  }\n\n  p {\n    color: var(--text-color, #2C2C2C);\nfont-size: 14px;\nfont-style: normal;\nfont-weight: 400;\nline-height: normal;\n  }\n\n\n  .link {\n    font-weight: 500;\n    color: #30AB89\n  }\n}\n","/*------------------------------------\nSECTION TESTIMONIAL\n-------------------------------------*/\n#section-testimonial {\n  position: relative;\n  padding: 20px;\n  -webkit-background-size: cover;\n  background-size: cover;\n  background-color: #101010;\n}\n.mb25 {\n  margin-bottom: 25px;\n}\n\n.testimonial-container {\n  margin: auto;\n  max-width: 1540px;\n\n  margin: 80px auto;\n  \n  @media (max-width: 1154px) {\n    margin: 50px auto;\n  }\n}\n\n.test-inner {\n  display: flex;\n  padding: 24px;\n  flex-direction: column;\n  justify-content: center;\n  align-items: flex-start;\n  gap: 22px;\n  color: var(--white-color, #fafafa);\n  font-size: 14px;\n  font-style: normal;\n  font-weight: 400;\n  line-height: normal;\n  border-radius: 32px;\n  border: 2px solid var(--main-color-1, #30ab89);\n  min-height: 254px;\n  height: 300px;\n  width: 500px;\n\n  @media screen and (max-width: 1200px) {\n    margin-bottom: 1rem;\n    height: 320px;\n    width: 420px;\n  }\n  @media screen and (max-width: 1000px) {\n    margin-bottom: 1rem;\n    height: 350px;\n    width: 320px;\n  }\n  @media screen and (max-width: 900px) {\n    margin-bottom: 1rem;\n    height: 350px;\n    width: 400px;\n  }\n  @media screen and (max-width: 500px) {\n    margin-bottom: 1rem;\n    height: 380px;\n    width: 320px;\n  }\n  @media screen and (max-width: 370px) {\n    margin-bottom: 1rem;\n    height: 400px;\n    width: 280px;\n  }\n}\n\n.test-author-thumb {\n  align-items: center;\n  gap: 1rem;\n  // margin-bottom: 15px;\n  img {\n    width: 56px;\n    height: 56px;\n    border-radius: 100%;\n    // border: 1px dotted #ddd;\n    padding: 5px;\n  }\n}\n\n#video-modal {\n  .test-author-thumb {\n    align-items: center;\n    gap: 1rem;\n    // margin-bottom: 15px;\n    .star-image {\n      width: 32px;\n      height: 32px;\n      border-radius: 100%;\n      // border: 1px dotted #ddd;\n      padding: 5px;\n    }\n  }\n}\n\n.test-author-info {\n  gap: 0.25rem;\n  h4 {\n    color: var(--white-color, #fafafa);\n    font-size: 18px;\n    font-style: normal;\n    font-weight: 600;\n    line-height: normal;\n    margin: 0;\n  }\n  h6 {\n    color: var(--white-color, #fafafa);\n    font-size: 10px;\n    font-style: normal;\n    font-weight: 400;\n    line-height: normal;\n    margin: 0;\n  }\n}\n\n/*----------------------\n TETSIMONIAL-2\n-------------------------*/\n\n.testimonial .content img {\n  margin: 0 auto 30px;\n  border: 3px solid $light;\n}\n\n.img-md {\n  width: 120px;\n  height: 120px;\n  border-radius: 100%;\n}\n.testimonals-slider .slick-dots {\n  display: flex !important;\n  justify-content: center;\n  left: 50%;\n  transform: translate(-55%, 0);\n  bottom: -50px !important;\n  top: auto;\n}\n.testimonial-next img,\n.testimonial-prev img {\n  filter: brightness(0) invert(1);\n}\n\n.thumbnail {\n  position: relative;\n  display: inline-block;\n  cursor: pointer;\n\n}\n\n.thumbnail::before {\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 100%;\n  height: 100%;\n  content: \"\";\n  background: linear-gradient(\n    180deg,\n    rgba(0, 0, 0, 0) 0%,\n    rgba(48, 171, 137, 1) 80%\n  );\n  border-radius: 1.5rem;\n}\n\n.thumbnail img {\n  width: 100%;\n  height: auto;\n  border-radius: 1.5rem;\n}\n.thumbnail .client-info {\n  position: absolute;\n  display: flex;\n  bottom: 20%;\n  left: 10%;\n  z-index: 100;\n  width: 100%;\n  height: 20px;\n  display: flex;\n  align-items: center;\n  gap: 1rem;\n\n  h4 {\n    color: black;\n    font-weight: 800;\n    font-size: 20px;\n  }\n}\n.thumbnail .client-info p {\n  margin-bottom: 0px;\n}\n\n.play-button{\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  cursor: pointer;\n  width: 40px;\n  height: 40px;\n  border-radius: 200px;\n  background-color: #30ab89;\n\n}\n.play-button:hover{\n\n  background-color: #095c44;\n\n}\n// .thumbnail .play-button {\n//   //   position: absolute;\n//   display: flex;\n//   justify-contentrgb(21, 134, 102)r;\n//   align-items: center;\n//   top: 50%;\n//   left: 50%;\n//   //   transform: translate(-50%, -50%);\n//   font-size: 2em;\n//   color: #30ab89;\n//   font-size: 16px;\n//   width: 48px;\n//   border-radius: 100%;\n//   height: 48px;\n//   background: #000000f0;\n//   text-shadow: 0 0 10px black;\n// }\n\n/* Modal styling */\n.modal {\n  display: none;\n  transition: all 300ms ease;\n  position: fixed;\n  z-index: 1000;\n  left: 0;\n  top: 5%;\n  width: 100%;\n  height: 100%;\n  overflow: hidden;\n  background-color: rgba(0, 0, 0, 0.7);\n \n}\n.modal-content {\n  position: absolute;\n  left: 50%;\n  top: 50%;\n  transform: translate(-50%, -50%);\n  padding: 32px;\n  width: 80%;\n  max-width: 600px;\n  border: 2px solid #1f6652;\n  border-bottom: 2px solid #288168;\n  background: linear-gradient(#000 90%,#214d40 100%);\n  border-radius: 8px;\n}\n.close {\n  position: absolute;\n  top: 0px;\n  right: 10px;\n  font-size: 2em;\n  color: white;\n  cursor: pointer;\n}\n.close:hover {\n  color: white;\n}\n\n#progress{\n  background-color: orange;\n}\n.player {\n  position: relative;\n  max-width: 750px;\n  margin: 20px auto;\n  box-shadow: 0 0 20px rgba(0, 0, 0, 0.2);\n}\n\n.viewer {\n  width: 100%;\n  height: auto;\n  border-radius: 5px;\n}\n\n.player__controls {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 10px;\n  background: #000;\n}\n\n.progress {\n  flex: 1;\n  height: 5px;\n  background: #ccc;\n  cursor: pointer;\n  margin-right: 10px;\n  position: relative;\n}\n\n.progress__filled {\n  width: 0;\n  height: 100%;\n  background: #30ab89;\n  transition: width 0.1s;\n}\n\n.player__button {\n  background: none;\n  transition: all 200ms ease;\n  border: 0;\n  margin-right: 5px;\n  color: #30ab89;\n  border-radius: 5px;\n  background-color: #30ab8836;\n  font-size: 20px;\n  cursor: pointer;\n}\n.player__button:hover {\n  background: #30ab8867;\n  \n  color: #3bc59e;\n  font-size: 20px;\n  cursor: pointer;\n}\n\n::-webkit-scrollbar {\n  width: 10px;\n  transition: all 200ms ease-in;\n}\n/* Track */\n::-webkit-scrollbar-track {\n  background: #0f1614;\n  padding-block: 5px;\n  border-radius: 100px;\n}\n/* Handle */\n::-webkit-scrollbar-thumb {\n  /* background: #888; */\n  background: #30ab89;\n  border-radius: 100px;\n}\n/* Handle on hover */\n::-webkit-scrollbar-thumb:hover {\n background: #1d745b;\n width: 17px;\n}","/*---------------------------\nCONTACT PAGE\n-----------------------------*/\n\n#contact-info {\n  padding-top: 90px;\n}\n.contact-info-block {\n  border: 1px solid $border-color;\n  padding: 40px 20px;\n  border-radius: 5px;\n\n  h4 {\n    margin-bottom: 0px;\n  }\n  i {\n    font-size: 40px;\n    margin-bottom: 20px;\n    display: block;\n    color: $primary-color;\n  }\n}\n\n.form-control:focus,\n.form-control:hover {\n  border-color: $primary-color;\n  box-shadow: none;\n}\n\na.lead {\n  color: inherit;\n}\n/* --------------\n    MAP\n-----------------*/\n\n#map {\n  height: 400px;\n  width: 100%;\n}\n.form-left-details {\n  .primary-heading {\n    font-size: 24px;\n    font-weight: 600;\n  }\n  .seconday-heading {\n    font-size: 16px;\n    font-weight: 500;\n    color: #21c87a;\n    margin-bottom: 8px;\n  }\n  .unordered-check-list {\n    padding-left: 2.25rem;\n    list-style: none;\n    li {\n      position: relative;\n      padding: 0.62rem 0;\n    }\n    li:before {\n        content: '';\n        position: absolute;\n        left: -2.25rem;\n        top: .9375rem;\n        width: 1.25rem;\n        height: 1.25rem;\n        background-image: url(../../images/icon/correct-icon.svg);\n        background-repeat: no-repeat;\n    }\n  }\n}\n.contact-section-title {\n    font-size: 28px;\n    max-width: 800px;\n    margin-bottom: 3rem !important;\n    margin: auto;\n    display: block;\n    text-align: center;\n    margin: auto;\n\n    @media (max-width:575px) {\n      font-size: 24px;\n    margin-bottom: 2rem !important;\n    }\n    \n    @media (max-width:400px) {\n      font-size: 20px;\n    margin-bottom: 1rem !important;\n    }\n}\n\n.contact_form {\n    padding: 3rem 2rem;\n    background: #fff;\n    box-shadow: 0px 0px 5px #ddd;\n    border-radius: .5rem;\n}","/*----------------------\n FOOTER\n-----------------------*/\n#footer {\n  padding: 70px 0px 30px;\n  position: relative;\n\n  .footer-brand .logo {\n    max-width: 20rem;\n  }\n\n  .footer-brand {\n    font-size: 30px;\n  }\n\n  .footer-links {\n    padding-left: 0;\n    list-style-type: none;\n  }\n}\n\n#footer {\n  background: url(\"../images/bg/10.jpg\");\n  -webkit-background-size: cover;\n  background-size: cover;\n}\n\n.footer-overlay {\n  background: #111;\n  opacity: 0.94;\n}\n\n.footer-widget {\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n}\n\n.social-icons {\n  margin-top: 14px;\n  img {\n    width: 20px;\n    margin-right: 1rem;\n  }\n}\n\n.primary-btn {\n  padding: 10px 28px;\n  border-radius: 24px;\n  background-color: #30ab89;\n  color: #fff;\n  font-size: 14px;\n  font-weight: 500;\n  line-height: 17px;\n  transition: 0.3s ease-in-out;\n  border: 2px solid #30ab89 !important;\n  position: relative;\n  .nav-link {\n    padding: 0px !important;\n  }\n}\n.primary-btn::after {\n  position: absolute;\n  width: 12px;\n  height: 14px;\n  right: -30px;\n  top: 50%;\n  transform: translate(0, -55%);\n  background: url(/images/icon/right-arrow.svg);\n  content: \"\";\n  transition: 0.3s ease-in-out;\n  opacity: 0;\n  filter: brightness(0) invert(1);\n}\n.primary-btn:hover {\n  background-color: transparent !important;\n  padding-left: 20px;\n  padding-right: 36px;\n  color: #30ab89 !important;\n  .nav-link {\n    color: #30ab89 !important;\n  }\n}\n.primary-btn:hover::after {\n  right: 20px;\n  opacity: 1;\n  filter: none;\n}\n.primary-btn:hover,\n.primary-btn:visited {\n  color: #fff;\n}\n\n.footer-links {\n  a {\n    color: $black-lighter;\n    line-height: 38px;\n    font-size: 14px;\n    text-transform: capitalize;\n  }\n}\n\n.footer-copy {\n  color: $black-lighter;\n  font-size: 16px;\n  position: relative;\n  margin-bottom: 0;\n  display: inline-block;\n\n  &:before {\n    position: absolute;\n    content: \"\";\n    right: calc(100% + 30px);\n    top: 16px;\n    width: 2000%;\n    height: 1px;\n    height: 1px;\n    background: #94959a;\n  }\n}\n.current-year {\n  color: $primary-color !important;\n}\n\n/*-----------------------------\n SCROLL TO TOP\n--------------------------------*/\n.scroll-to-top.green {\n  position: fixed;\n  content: \"\";\n  right: 30px;\n  bottom: 50px;\n  z-index: 999;\n  background: #30ab89;\n  color: $light !important;\n  border-radius: 100%;\n  opacity: 0;\n\n  i {\n    width: 50px;\n    height: 50px;\n    border-radius: 100%;\n    text-align: center;\n    font-size: 22px;\n    line-height: 50px;\n    display: block;\n    -webkit-box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n    box-shadow: 0 7px 22px rgba(0, 0, 0, 0.08);\n  }\n}\n\n.scroll-to-top:hover,\n.scroll-to-top:focus {\n  text-decoration: none;\n}\n\n.reveal {\n  transition: all 0.3s;\n  cursor: pointer;\n  opacity: 1 !important;\n}\n\n.mt-4-mobile {\n  @media (max-width: 480px) {\n    margin-top: 1rem;\n  }\n}\n\n.handle-side-navbar {\n  position: fixed;\n  content: \"\";\n  left: 5%;\n  bottom: 7rem;\n  z-index: 999;\n  color: $light !important;\n  border-radius: 100%;\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n  opacity: 0;\n  @media (max-width: 1325px) {\n    display: none;\n  }\n}\n.handle-side-navbar::before {\n  position: absolute;\n  bottom: -3.2rem;\n  height: 100px;\n  width: 2px;\n  content: \"\";\n  background: #a8a7a7;\n  left: 50%;\n  transform: translate(0, 55%);\n}\n","/*----------------------------------\n    MEDIUM LAYOUT: 1280px\n-----------------------------------*/\n@include large-desktop {\n  .navbar {\n    text-align: center;\n  }\n\n\n  .navbar .nav-item-divider {\n    display: block;\n  }\n  .process-block {\n    width: 200px;\n    margin: auto;\n  }\n  .alumni {\n    background-position: 100%;\n  }\n  .section-title {\n    font-size: 20px;\n  }\n  #service-subheading {\n    width: 100%;\n  }\n}\n\n@media (max-width: 1010px) {\n  .section-title {\n    font-size: 20px;\n  }\n  .stats {\n    flex: 0 0 10%;\n    max-width: 40%;\n  }\n\n}\n@media (max-width: 991px) {\n.img-cont img{\n  height: 400px;\n  margin: auto;\n  width: auto;\n  transform: translateY(0%);\n}\n.slider-container{\n  height: auto;\n}\n}\n\n@media (max-width: 767px) {\n  .img-cont img{\n    height: 300px;\n  }\n\n  }\n\n  @media (max-width: 823px){\n    #plantImg{\n      transform: translateY(0%) !important;\n    }\n  }\n  @media (max-width: 732px){\n    #plantImg{\n      transform: translateY(0%) !important;\n    }\n  }\n  @media (max-width: 600px){\n    #plantImg{\n      transform: translateY(0%) !important;\n    }\n  }\n  @media (max-width: 538px){\n    #plantImg{\n      transform: translateY(10%) !important;\n    }\n  }\n  @media (max-width: 524px){\n    #plantImg{\n      transform: translateY(18%) !important;\n    }\n  }\n  @media (max-width: 480px){\n    #plantImg{\n      transform: translateY(0%) !important;\n    }\n  }\n  @media (max-width: 456px){\n    #plantImg{\n      transform: translateY(0%) !important;\n    }\n  }\n  @media (max-width: 399px){\n    #plantImg{\n      transform: translateY(14%) !important;\n    }\n  }\n  @media (max-width: 312px){\n    #plantImg{\n      transform: translateY(22%) !important;\n    }\n  }\n/*----------------------------------\n    TABLET LAYOUT: 768px\n------------------------------------*/\n@include desktop {\n\n  #plantImg{\n    transform: translateY(0%);\n  }\n  .bottom-bar{\n    h2{\n      font-size: 30px;\n    }\n    p{\n      font-size: 16px;\n    }\n  }\n  #companies-container {\n    max-width: 650px;\n  }\n  #bytecorpimg {\n    width: 25%;\n  }\n  #Foliologo {\n    width: 75%;\n  }\n  #nustlogo {\n    width: 30%;\n  }\n  #JafferLogo {\n    width: 60%;\n  }\n\n\n  .alumni {\n    background-position: 120%;\n  }\n\n  .stats {\n    max-width: 35%;\n  }\n\n  #section-para {\n    margin-bottom: 5rem;\n  }\n\n  .section-title {\n    font-size: 30px;\n  }\n\n  .background-text {\n    font-size: 60px;\n  }\n\n  .main-banner h1.display-4 {\n    line-height: 62px;\n    font-size: 30px;\n  }\n\