weight: 700;\n}\n@media screen and (max-width: 1108px) {\n  .workFlow-heading h3 {\n    font-size: 45px;\n  }\n}\n@media screen and (max-width: 1102px) {\n  .workFlow-heading h3 {\n    font-size: 40px;\n  }\n}\n@media screen and (max-width: 1102px) {\n  .workFlow-heading h3 {\n    font-size: 35px;\n  }\n}\n@media screen and (max-width: 804px) {\n  .greenHorizontalLine {\n    display: none;\n  }\n}\n.workFlow-body {\n  // background: rgba(255, 255, 255, 0.5) url(../../images/workFlow/Bg\\ logo.png)\n  //   no-repeat;\n  background-position: center;\n  position: relative;\n}\n.workFlow-body .workflowContainer {\n  //   background: $green-border;\n  border-radius: 10px;\n  padding-top: 6px;\n  //   padding: 6px;\n  box-sizing: border-box;\n  border-radius: 10px;\n  //   padding: 10px;\n  font-size: 19px;\n  box-sizing: border-box;\n  //   margin-top: 1rem;\n  color: black;\n  font-weight: 400px;\n\n  max-width: 405px;\n}\n.workFlow-body h3 {\n  color: var(--heading-color, #202020);\ntext-align: center;\nfont-family: Plus Jakarta Sans;\nfont-size: 24px;\nfont-style: normal;\nfont-weight: 600;\nline-height: 35px; /* 145.833% */\nmargin: 0;\ntext-align: end;\nmax-width: 405px;\n\n}\n.completeCard {\n  display: flex;\n  justify-content: space-between;\n  align-items: flex-start;\n  gap: 4rem;\n}\n.allCards {\n  position: absolute;\n  top: 0;\n  left: 50%;\n  display: flex;\n  flex-direction: column;\n  justify-content: space-evenly;\n  transform: translate(-72%, 0);\n  height: 100%;\n  min-height: 1501px;\n  // width: 100%;\n  // height: 1501px;\n}\n.imageContainer {\n  transform: translateY(-15px);\n  width: 143px;\n  height: 83px;\n}\n.evencompleteCard {\n  display: flex;\n  justify-content: space-between;\n  align-items: flex-start;\n  gap: 2rem;\n  transform: translateX(45%);\n}\n.evencompleteCard h3,\n.evencompleteCard div {\n  text-align: left;\n}\n@media screen and (max-width: 1300px) {\n  .workFlow-body .workflowContainer {\n    width: 550px;\n  }\n}\n@media screen and (max-width: 1200px) {\n  .workFlow-body .workflowContainer {\n    width: 500px;\n  }\n  .workFlow-body h3 {\n    font-size: 25px;\n  }\n  .allCards {\n    transform: translate(-70%, 0);\n  }\n  .evencompleteCard {\n    transform: translateX(40%);\n  }\n}\n@media screen and (max-width: 1070px) {\n  .workFlow-body h3 {\n    font-size: 19px;\n  }\n  .workFlow-body .workflowContainer {\n    font-size: 16px;\n  }\n  .workFlow-body .workflowContainer {\n    width: 400px;\n  }\n  .allCards {\n    transform: translate(-78%, 0);\n  }\n  .evencompleteCard {\n    transform: translateX(55%);\n  }\n  .imageContainer {\n    width: 110px;\n  }\n}\n@media screen and (max-width: 850px) {\n  .workflowCenterStick {\n    width: 18px;\n  }\n  .workFlow-body h3 {\n    font-size: 16px;\n  }\n  .workFlow-body .workflowContainer {\n    width: 250px;\n    font-size: 12px;\n    margin-top: 0.5rem;\n  }\n  .imageContainer {\n    width: auto;\n    height: auto;\n    transform: translateY(0);\n  }\n  .imageContainer > img {\n    width: 90px;\n  }\n  .completeCard {\n    justify-content: center;\n    gap: 2rem;\n  }\n  .allCards {\n    transform: translate(-70%, 0);\n    min-height: 900px;\n  }\n  .evencompleteCard {\n    transform: translateX(40%);\n    justify-content: center;\n    // gap: .5rem;\n  }\n  .evencompleteCard > .imageContainer > img {\n    text-align: right;\n  }\n}\n@media screen and (max-width: 560px) {\n  .workFlow-body .workflowContainer {\n    width: 150px;\n    font-size: 9px;\n  }\n  .allCards {\n    transform: translate(-65%, 0);\n  }\n  .imageContainer > img {\n    width: 70px;\n  }\n  .workFlow-body h3 {\n    width: 150px;\n    font-size: 12px;\n    line-height: 20px;\n  }\n  .evencompleteCard {\n    transform: translateX(34%);\n  }\n}\n",".service-content h1 {\n  color: #1b1b1b;\n  // font-family: Poppins;\n  font-size: 32px;\n  font-style: normal;\n  font-weight: 600;\n  line-height: 50px; /* 142.857% */\n}\n.service-content h1 span {\n  color: #30AB89;\n  font-wei