ms: center;\n  align-items: center;\n  padding: 40px 20px;\n  border-radius: 10px;\n  \n  h2, p {\n    color: white;\n  }\n  \n  .gif-container{\n    transition: transform 200ms ease;\n    margin-block: 2rem;\n    max-width: 450px;\n    width: 100%;\n    max-height: 200px;\n    background-color: #ffffff5d;\n    border-radius: 15px;\n    padding: 10px 20px;\n    object-fit: contain;\n  }\n\n  img{\n    width: 100%;\n    height: 100%;\n    object-fit: contain;\n    border-radius: 10px;\n  }\n\n  button{\n    background-color: transparent;\n    border: 2px solid white;\n    color: white;\n    font-weight: 800;\n    padding: 10px 30px;\n    transition: all 200ms ease;\n  }\n  \n\n  @media (max-width: 1250px){\n    max-width: 450px;\n    padding-inline: 10px;\n    h2{\n      font-size: 20px;\n    }\n    p{\n      font-size: 12px;\n    }\n    .gif-container{\n      max-width: 350px;\n    }\n    \n    button{\n      font-size: 12px;\n      padding: 10px 30px;\n    }\n  }\n  @media (max-width: 750px){\n    max-width: 300px;\n    padding-inline: 10px;\n    h2{\n      font-size: 20px;\n    }\n    p{\n      font-size: 12px;\n    }\n    .gif-container{\n\n      max-width: 250px;\n      max-height: 150px;\n      margin-block: 1rem;\n    }\n\n    button{\n      font-size: 12px;\n      padding: 10px 30px;\n    }\n  }\n}\n.impact-card:hover .gif-container{\n  transform: scale(1.01);\n}\n.tabs{\n  padding: 30px 10px;\n  @media (max-width: 1024px){\n    display: flex;\n    width: 100%;\n    justify-content: center;\n  \n  }\n  @media (max-width: 500px){\n    padding: 20px 0px;\n  \n  }\n}\n.tab-button{\n  background-color: transparent;\n  border: none;\n  font-weight: normal;\n  color: #5c5c5c;\n  padding: 0px 20px;\n  transition: all 200ms ease;\n  @media (max-width: 1024px){\n    padding: 0px 5px;\n  \n  }\n}\n\n.tab-button:nth-child(1){\n  width: 100%;\n  max-width: 200px;\n  @media (max-width: 1024px){\n    max-width: 150px;\n    font-size: 12px;\n    \n  }\n  @media (max-width: 500px){\n    max-width: 140px;\n    font-size: 12px;\n    \n  }\n}\n.tab-button:nth-child(2){\n  border-left: 1px solid black;\n  width: 100%;\n  max-width: 250px;\n  @media (max-width: 1024px){\n    max-width: 190px;\n    font-size: 12px;\n    \n  }\n  @media (max-width: 500px){\n    max-width: 180px;\n    font-size: 12px;\n    \n  }\n}\n\n.tab-button[data-isActive = \"true\"]{\n  color: black;\n  font-weight: 600;\n}\n\n.tab-button:focus{\n  outline: none;\n}\n.tabs-container{\n  position: relative;\n}\n.tab-content {\n  opacity: 0;\n  pointer-events: none;\n  position: absolute;\n  transition: opacity 0.1s ease;\n}\n\n.tab-content.active {\n  opacity: 1;\n  pointer-events: auto;\n  position: relative;\n}",".map {\n  background: #101010;\n}\n.map .earn-trust {\n  margin-bottom: 40px !important;\n}\n.map .map-wrapper {\n  position: relative;\n}\n.map .map-icons {\n  width: 6px;\n  height: 6px;\n  position: absolute;\n  background-color: #A4E7D4;\n  border-radius: 50%;\n  transform: translate(-55%, -55%);\n  animation: 1.4s ease-out -1.4s infinite alternate forwards map-glowing;\n}\n.map .map-icons.usa {\n  top: 45%;\n  left: 17.75%;\n}\n.map .map-icons.france {\n  top: 36%;\n  left: 48.65%;\n}\n.map .map-icons.columbia {\n  top: 34.9%;\n  left: 52.8%;\n}\n.map .map-icons.saudia {\n  top: 51.7%;\n  left: 58.6%;\n}\n.map .map-icons.pakistan {\n  top: 51.7%;\n  left: 68.2%;\n}\n.map .map-icons.sa {\n  top: 84.6%;\n  left: 52.8%;\n}\n.map .map-icons.aus {\n  top: 73.6%;\n  left: 88%;\n}\n.map .map-icons.japan {\n  top: 43.6%;\n  left: 88.4%;\n}\n@keyframes map-glowing {\n  0% {\n    box-shadow: 0px 0px 1px 0px #A4E7D488;\n  }\n  100% {\n    box-shadow: 0px 0px 1px 5px #A4E7D488;\n  }\n}\n",".technology-slider {\n  width: 100%;\n}\n.technology-slide {\n  padding: 45px 54px;\n  width: 200px;\n  height: 200px;\n  display: flex;\n  justify-content: center;\n  margin: auto;\n  border: 1px solid var(--stroke, #c8c8c8);\n  border-radius: 32px;\n  @media (max-width: 991px) {\n    padding: 30px 50px;\n  }\n  @media (max-width: 767px) {\n    padding: 30px 35px;\n    width: 150px;\n    height: 150px;\n  }\n}\n.technology-slide .technology-box {\n  gap: 24px;\n  width: fit-content;\n  @media (max-width: 767px) {\n    gap: 16px;\n  }\n}\n.technology-slide .technology-box p {\n  margin-bottom: 0px !important;\n  @media (max-width: 767px) {\n    font-size: 16px;\n  }\n}\n.technology-slide .technology-box img {\n  object-fit: contain;\n  @media (max-width: 767px) {\n    height: 50px;\n    width: 50px;\n  }\n}\n.slider-prev,\n.slider-next {\n  background-color: transparent;\n  border: 0px;\n}\n.slider-prev:focus,\n.slider-next:focus {\n  outline: none;\n}\n.slider-prev {\n  transform: scaleX(-1);\n}\n.technology-arrow {\n  margin: 40px 0;\n  @media (max-width: 991px) {\n    margin: 20px 0;\n  }\n}\n",".what-we-offer .accordion-btn {\n  width: 100%;\n  text-align: left;\n  padding-left: 0px;\n  padding-top: 24px;\n  padding-bottom: 24px;\n  font-size: 18px;\n  color: var(--text-color, #2c2c2c);\n  font-weight: 500;\n  text-transform: capitalize;\n  position: relative;\n}\n.what-we-offer #service-heading {\n    @media (max-width: 991px) {\n        text-align: center;\n    }\n}\n.what-we-offer .accordion-btn::after {\n  position: absolute;\n  content: \"\";\n  right: 0;\n  top: 28px;\n  width: 20px;\n  height: 20px;\n  background: url(/images/services-page/ph_plus-light.svg);\n  opacity: 0;\n  animation: 1s customAccordionAnimation ease-in-out forwards;\n}\n\n.accordion-btn:not(.collapsed)::after {\n  background: url(/images/services-page/ph_minus.svg);\n  animation: 1s customAccordionAnimation ease-in-out forwards;\n}\n@keyframes customAccordionAnimation {\n    0% {\n        opacity: .5;\n    }\n    100% {\n        opacity: 1;\n    }\n}\n.what-we-offer .accordion-btn:hover {\n  text-decoration: none;\n}\n.what-we-offer .card-header {\n  padding: 0;\n  border: 0px;\n  background: transparent;\n}\n.what-we-offer .card {\n  border: 0;\n  border-bottom